/// Direct GG-topology → WebAssembly AOT emitter — the wasm sibling of
/// `aot_c.rs`, and the real implementation behind the `wasm_emitter`
/// node declared in `betti.gg`. It recognizes the same certified
/// classes (benchmark fixtures + the certified numeric-loop class) and
/// FAILS CLOSED for every other topology.
///
/// Emitted modules conform to the existing gnosis WASM ABIs consumed by
/// `gnosis/src/wasm-execution-bridge.ts` — no new host glue anywhere:
///
/// - `scalar-v1` (numeric-loop class): export `main(f64…) -> f64` plus a
///   `memory` export for manifest uniformity. Zero imports.
/// - `json-v1` (echo / fibonacci / fanout fixtures): exports `memory`,
///   `gnosis_alloc(len) -> ptr`, `main(ptr, len) -> out_ptr`,
///   `gnosis_result_len() -> len`, `gnosis_free(ptr, len)` (no-op; bump
///   allocator). Output bytes are VALID JSON. Zero imports.
/// - `json-v1` also carries the certified **scalar-string** class
///   (`certified_class: "scalar-string"`): a single exported function
///   over ONE object parameter with `input.field` string/number reads,
///   string locals, template-literal / `+` concatenation, string
///   equality, `if`/`else`, and the numeric expression subset. Same
///   exports and decline discipline as the fixture modules. See the
///   scalar-string section below for the exact accepted grammar.
///
/// Parity discipline (the aot_c `exit(3)` rule, translated):
/// - **Decline = trap (`unreachable`).** Anywhere the compiled module's
///   answer could diverge from the walker — unparseable input, escaped
///   JSON strings, fuel exhaustion, out-of-bounds indexes, implicit JS
///   `undefined` — the module traps and the host falls back to the
///   interpreter. The wasm lane never answers where it could disagree.
/// - Where the C lane must decline because C semantics are undefined or
///   implementation-defined, wasm often mirrors the walker EXACTLY and
///   keeps answering: `i64.trunc_sat_f64_s` is bit-for-bit Rust's
///   saturating `as` cast, so the bitwise family needs no 2^32 domain
///   fence; f64 arithmetic and comparisons are IEEE-identical. The
///   decline sets of the two AOT lanes intentionally differ; the parity
///   contract is only ever against the walker.
const FUEL_INIT: i64 = 1 << 42;

/// Base offset for static data (JSON needles, literal segments). The
/// first 16 bytes stay zero as a null guard.
const DATA_BASE: u32 = 16;
/// Scratch region for digit formatting in json-v1 number output.
const SCRATCH_BASE: u32 = 128;
/// First byte the json-v1 bump allocator will hand out.
const HEAP_BASE: i32 = 1024;
/// First byte available to numeric-loop array storage.
const ARRAY_BASE: u32 = 16;
const WASM_PAGE: u64 = 65536;

pub const BETTI_WASM_ARTIFACT_VERSION: &str = "betti-wasm/1";
/// Custom-section name carrying the manifest JSON (self-describing
/// artifact; mirrors the .ggc PackedKnot+CBOR trailer idea).
pub const BETTI_WASM_MANIFEST_SECTION: &str = "gnosis-betti-manifest";

// ── Manifest (the `betti-wasm/1` contract; see
//    gnosis/src/betti-wasm-manifest.ts for the consuming validator) ──

#[derive(Debug, Clone, Serialize)]
pub struct BettiWasmLimits {
    #[serde(rename = "memoryPagesMax")]
    pub memory_pages_max: u32,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub fuel: Option<u64>,
}

#[derive(Debug, Clone, Serialize)]
pub struct BettiWasmManifest {
    pub artifact_version: &'static str,
    #[serde(rename = "artifactId")]
    pub artifact_id: String,
    #[serde(rename = "topologyHash")]
    pub topology_hash: String,
    #[serde(rename = "sourceHash")]
    pub source_hash: String,
    pub language: String,
    #[serde(rename = "filePath")]
    pub file_path: String,
    #[serde(rename = "functionName")]
    pub function_name: String,
    pub certified_class: &'static str,
    pub tier: &'static str,
    /// Always empty for BOTH tiers that use this manifest — `certified-direct`
    /// (this module's emitted wasm) and `interpreter-embed` (the reused
    /// `gg-walker-wasm` cdylib, `aot_gg_embed.rs`): modules are self-contained,
    /// zero-import, so Workers/swerve/wasmtime instantiate with `{}`.
    pub imports: Vec<serde_json::Value>,
    pub pure: bool,
    pub limits: BettiWasmLimits,
    /// Integrity fields cover the CORE module bytes — the module
    /// EXCLUSIVE of the `gnosis-betti-manifest` custom section (the
    /// section cannot hash itself).
    #[serde(rename = "byteLength")]
    pub byte_length: u64,
    pub sha256: String,
    pub decline_semantics: &'static str,
    pub wasm_opt: bool,
    pub export_name: &'static str,
    pub abi: &'static str,
    pub memory_export: &'static str,
    pub alloc_export: &'static str,
    pub result_length_export: &'static str,
    pub free_export: &'static str,
}

#[derive(Debug, Clone)]
pub struct EmittedWasm {
    /// Full module bytes: core module + trailing manifest custom section.
    pub bytes: Vec<u8>,
    pub manifest: BettiWasmManifest,
}

impl EmittedWasm {
    pub fn manifest_json(&self) -> String {
        serde_json::to_string_pretty(&self.manifest)
            .expect("betti-wasm manifest serializes infallibly")
    }
}

// ── Public API (mirrors aot_c) ──────────────────────────────────────

pub fn emit_wasm_for_export(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
) -> Result<EmittedWasm> {
    let entry = scan
        .scan_result
        .topologies
        .iter()
        .find(|topology| topology.function_name == export_name)
        .with_context(|| format!("export '{export_name}' not found"))?;

    let (core, class, abi, pages_max, fuel) = if is_echo_fixture(scan, entry) {
        (emit_echo_module(), "echo", "json-v1", 64u32, None)
    } else if is_fibonacci_fixture(scan, entry) {
        (
            emit_fibonacci_module(),
            "fibonacci",
            "json-v1",
            64,
            Some(FUEL_INIT as u64),
        )
    } else if is_fanout_fixture(entry) {
        (emit_fanout_module(), "fanout", "json-v1", 64, None)
    } else if let Some(module) = numeric_loop_wasm(source, export_name) {
        let pages = module.pages;
        (
            module.bytes,
            "numeric-loop",
            "scalar-v1",
            pages as u32,
            Some(FUEL_INIT as u64),
        )
    } else if let Some(module) = string_class_wasm(source, export_name) {
        let pages = module.pages;
        (
            module.bytes,
            "scalar-string",
            "json-v1",
            (pages as u32).max(64),
            None,
        )
    } else {
        bail!(
            "WASM AOT emitter supports the benchmark fixtures (echo.ts, fib.ts, fanout.gg) \
             and the certified numeric-loop and scalar-string classes; this topology is in neither"
        )
    };

    let sha256 = sha256_hex(&core);
    let byte_length = core.len() as u64;
    let artifact_id = fingerprint_aot_wasm(scan, source, export_name, &core)?;
    let topology_hash = topology_fingerprint(scan)?;
    let source_hash = format!("{:016x}", fnv1a64(source.as_bytes()));

    let manifest = BettiWasmManifest {
        artifact_version: BETTI_WASM_ARTIFACT_VERSION,
        artifact_id,
        topology_hash,
        source_hash,
        language: scan.scan_result.language.clone(),
        file_path: scan.scan_result.file_path.clone(),
        function_name: export_name.to_string(),
        certified_class: class,
        tier: "certified-direct",
        imports: Vec::new(),
        pure: true,
        limits: BettiWasmLimits {
            memory_pages_max: pages_max,
            fuel,
        },
        byte_length,
        sha256,
        decline_semantics: "trap",
        wasm_opt: false,
        export_name: "main",
        abi,
        memory_export: "memory",
        alloc_export: "gnosis_alloc",
        result_length_export: "gnosis_result_len",
        free_export: "gnosis_free",
    };

    let manifest_json = serde_json::to_vec(&manifest).context("serialize betti-wasm manifest")?;
    let bytes = append_manifest_section(core, &manifest_json);

    Ok(EmittedWasm { bytes, manifest })
}

pub fn supports_wasm_for_export(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
) -> bool {
    let Some(entry) = scan
        .scan_result
        .topologies
        .iter()
        .find(|topology| topology.function_name == export_name)
    else {
        return false;
    };
    is_echo_fixture(scan, entry)
        || is_fibonacci_fixture(scan, entry)
        || is_fanout_fixture(entry)
        || numeric_loop_wasm(source, export_name).is_some()
        || string_class_wasm(source, export_name).is_some()
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CachedAotWasmArtifact {
    pub fingerprint: String,
    pub wasm_path: PathBuf,
    pub manifest_path: PathBuf,
    pub cache_hit: bool,
}

pub fn default_cache_dir() -> PathBuf {
    if let Ok(value) = std::env::var("MONSTER_AOT_WASM_CACHE_DIR") {
        return PathBuf::from(value);
    }
    if let Ok(value) = std::env::var("XDG_CACHE_HOME") {
        return PathBuf::from(value).join("gnosis").join("monster-aot-wasm");
    }
    if let Ok(value) = std::env::var("HOME") {
        return PathBuf::from(value)
            .join(".cache")
            .join("gnosis")
            .join("monster-aot-wasm");
    }
    std::env::temp_dir().join("gnosis-monster-aot-wasm")
}

pub fn prepare_cached_wasm(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
    cache_dir: &Path,
) -> Result<CachedAotWasmArtifact> {
    let emitted = emit_wasm_for_export(scan, source, export_name)?;
    let fingerprint = emitted.manifest.artifact_id.clone();
    let source_key = source_cache_key(&scan.scan_result.file_path, source, export_name);
    let wasm_path = cache_dir.join(format!("{fingerprint}.wasm"));
    let manifest_path = cache_dir.join(format!("{fingerprint}.manifest.json"));
    let source_key_path = cache_dir.join(format!("{source_key}.key"));

    fs::create_dir_all(cache_dir)
        .with_context(|| format!("failed to create AOT wasm cache {}", cache_dir.display()))?;

    if wasm_path.exists() && manifest_path.exists() {
        fs::write(&source_key_path, &fingerprint).with_context(|| {
            format!(
                "failed to write AOT wasm source-key index {}",
                source_key_path.display()
            )
        })?;
        return Ok(CachedAotWasmArtifact {
            fingerprint,
            wasm_path,
            manifest_path,
            cache_hit: true,
        });
    }

    fs::write(&wasm_path, &emitted.bytes)
        .with_context(|| format!("failed to write AOT wasm module {}", wasm_path.display()))?;
    fs::write(&manifest_path, emitted.manifest_json()).with_context(|| {
        format!(
            "failed to write AOT wasm manifest {}",
            manifest_path.display()
        )
    })?;
    fs::write(&source_key_path, &fingerprint).with_context(|| {
        format!(
            "failed to write AOT wasm source-key index {}",
            source_key_path.display()
        )
    })?;

    Ok(CachedAotWasmArtifact {
        fingerprint,
        wasm_path,
        manifest_path,
        cache_hit: false,
    })
}

pub fn lookup_cached_wasm(
    file_path: &str,
    source: &str,
    export_name: &str,
    cache_dir: &Path,
) -> Option<CachedAotWasmArtifact> {
    let source_key = source_cache_key(file_path, source, export_name);
    let fingerprint = fs::read_to_string(cache_dir.join(format!("{source_key}.key"))).ok()?;
    let fingerprint = fingerprint.trim().to_string();
    if fingerprint.is_empty() {
        return None;
    }
    let wasm_path = cache_dir.join(format!("{fingerprint}.wasm"));
    let manifest_path = cache_dir.join(format!("{fingerprint}.manifest.json"));
    if !wasm_path.exists() || !manifest_path.exists() {
        return None;
    }
    Some(CachedAotWasmArtifact {
        fingerprint,
        wasm_path,
        manifest_path,
        cache_hit: true,
    })
}

fn source_cache_key(file_path: &str, source: &str, export_name: &str) -> String {
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"monster-aot-wasm-source-v1\0");
    bytes.extend_from_slice(file_path.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(export_name.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(source.as_bytes());
    format!("{:016x}", fnv1a64(&bytes))
}

fn fingerprint_aot_wasm(
    scan: &PolyglotOrchestrationResult,
    source: &str,
    export_name: &str,
    core_bytes: &[u8],
) -> Result<String> {
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"monster-aot-wasm-v1\0");
    bytes.extend_from_slice(export_name.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(scan.scan_result.file_path.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(scan.scan_result.language.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(source.as_bytes());
    bytes.push(0);
    bytes.extend_from_slice(core_bytes);
    bytes.push(0);
    let topology_json =
        serde_json::to_vec(scan).context("failed to serialize AOT wasm topology")?;
    bytes.extend_from_slice(&topology_json);
    Ok(format!("{:016x}", fnv1a64(&bytes)))
}

fn topology_fingerprint(scan: &PolyglotOrchestrationResult) -> Result<String> {
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"monster-topology-v1\0");
    let topology_json =
        serde_json::to_vec(scan).context("failed to serialize topology for hashing")?;
    bytes.extend_from_slice(&topology_json);
    Ok(format!("{:016x}", fnv1a64(&bytes)))
}

/// Append the manifest custom section to finished core bytes. Custom
/// sections are self-delimiting, so raw concatenation is a valid module
/// transform (id 0x00, LEB128 payload size, LEB128 name length, name,
/// data) — no re-encode of the core module required.
pub(crate) fn append_manifest_section(mut core: Vec<u8>, manifest_json: &[u8]) -> Vec<u8> {
    let name = BETTI_WASM_MANIFEST_SECTION.as_bytes();
    let mut payload = Vec::with_capacity(name.len() + manifest_json.len() + 5);
    leb128_u32(&mut payload, name.len() as u32);
    payload.extend_from_slice(name);
    payload.extend_from_slice(manifest_json);
    core.push(0);
    leb128_u32(&mut core, payload.len() as u32);
    core.extend_from_slice(&payload);
    core
}

fn leb128_u32(out: &mut Vec<u8>, mut value: u32) {
    loop {
        let byte = (value & 0x7f) as u8;
        value >>= 7;
        if value == 0 {
            out.push(byte);
            return;
        }
        out.push(byte | 0x80);
    }
}

// ── SHA-256 (FIPS 180-4), hand-rolled to keep the emitter dependency-
//    free. Pinned against the NIST "abc" vector in tests. ──────────────

pub(crate) fn sha256_hex(data: &[u8]) -> String {
    const K: [u32; 64] = [
        0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4,
        0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe,
        0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f,
        0x4a7484aa, 0x5cb0a9dc, 0x76f988da, 0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7,
        0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc,
        0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b,
        0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070, 0x19a4c116,
        0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
        0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7,
        0xc67178f2,
    ];
    let mut h: [u32; 8] = [
        0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab,
        0x5be0cd19,
    ];
    let mut message = data.to_vec();
    let bit_len = (data.len() as u64).wrapping_mul(8);
    message.push(0x80);
    while message.len() % 64 != 56 {
        message.push(0);
    }
    message.extend_from_slice(&bit_len.to_be_bytes());

    let mut w = [0u32; 64];
    for chunk in message.chunks_exact(64) {
        for (i, word) in w.iter_mut().take(16).enumerate() {
            *word = u32::from_be_bytes([
                chunk[i * 4],
                chunk[i * 4 + 1],
                chunk[i * 4 + 2],
                chunk[i * 4 + 3],
            ]);
        }
        for i in 16..64 {
            let s0 = w[i - 15].rotate_right(7) ^ w[i - 15].rotate_right(18) ^ (w[i - 15] >> 3);
            let s1 = w[i - 2].rotate_right(17) ^ w[i - 2].rotate_right(19) ^ (w[i - 2] >> 10);
            w[i] = w[i - 16]
                .wrapping_add(s0)
                .wrapping_add(w[i - 7])
                .wrapping_add(s1);
        }
        let [mut a, mut b, mut c, mut d, mut e, mut f, mut g, mut hh] = h;
        for i in 0..64 {
            let s1 = e.rotate_right(6) ^ e.rotate_right(11) ^ e.rotate_right(25);
            let ch = (e & f) ^ ((!e) & g);
            let temp1 = hh
                .wrapping_add(s1)
                .wrapping_add(ch)
                .wrapping_add(K[i])
                .wrapping_add(w[i]);
            let s0 = a.rotate_right(2) ^ a.rotate_right(13) ^ a.rotate_right(22);
            let maj = (a & b) ^ (a & c) ^ (b & c);
            let temp2 = s0.wrapping_add(maj);
            hh = g;
            g = f;
            f = e;
            e = d.wrapping_add(temp1);
            d = c;
            c = b;
            b = a;
            a = temp1.wrapping_add(temp2);
        }
        h[0] = h[0].wrapping_add(a);
        h[1] = h[1].wrapping_add(b);
        h[2] = h[2].wrapping_add(c);
        h[3] = h[3].wrapping_add(d);
        h[4] = h[4].wrapping_add(e);
        h[5] = h[5].wrapping_add(f);
        h[6] = h[6].wrapping_add(g);
        h[7] = h[7].wrapping_add(hh);
    }
    h.iter().map(|word| format!("{word:08x}")).collect()
}

// ── Module assembly ─────────────────────────────────────────────────

enum GlobalInit {
    I32(i32),
    I64(i64),
}

struct FuncSpec {
    params: Vec<ValType>,
    results: Vec<ValType>,
    locals: Vec<ValType>,
    ins: Vec<I<'static>>,
}

struct ModuleSpec {
    pages_min: u64,
    globals: Vec<GlobalInit>,
    data: Vec<(u32, Vec<u8>)>,
    funcs: Vec<FuncSpec>,
    /// (export name, function index). Memory 0 is always exported as
    /// "memory".
    func_exports: Vec<(&'static str, u32)>,
}

fn assemble(spec: &ModuleSpec) -> Vec<u8> {
    let mut types = TypeSection::new();
    let mut ty_index: Vec<(Vec<ValType>, Vec<ValType>)> = Vec::new();
    let mut functions = FunctionSection::new();
    let mut code = CodeSection::new();

    for func in &spec.funcs {
        let key = (func.params.clone(), func.results.clone());
        let ty = match ty_index.iter().position(|existing| *existing == key) {
            Some(index) => index as u32,
            None => {
                types
                    .ty()
                    .function(func.params.iter().copied(), func.results.iter().copied());
                ty_index.push(key);
                (ty_index.len() - 1) as u32
            }
        };
        functions.function(ty);
        let mut body = Function::new_with_locals_types(func.locals.iter().copied());
        for instruction in &func.ins {
            body.instruction(instruction);
        }
        body.instruction(&I::End);
        code.function(&body);
    }

    let mut memory = MemorySection::new();
    memory.memory(MemoryType {
        minimum: spec.pages_min,
        maximum: None,
        memory64: false,
        shared: false,
        page_size_log2: None,
    });

    let mut globals = GlobalSection::new();
    for init in &spec.globals {
        match init {
            GlobalInit::I32(value) => globals.global(
                GlobalType {
                    val_type: ValType::I32,
                    mutable: true,
                    shared: false,
                },
                &ConstExpr::i32_const(*value),
            ),
            GlobalInit::I64(value) => globals.global(
                GlobalType {
                    val_type: ValType::I64,
                    mutable: true,
                    shared: false,
                },
                &ConstExpr::i64_const(*value),
            ),
        };
    }

    let mut exports = ExportSection::new();
    exports.export("memory", ExportKind::Memory, 0);
    for (name, index) in &spec.func_exports {
        exports.export(name, ExportKind::Func, *index);
    }

    let mut data = DataSection::new();
    for (offset, bytes) in &spec.data {
        data.active(
            0,
            &ConstExpr::i32_const(*offset as i32),
            bytes.iter().copied(),
        );
    }

    let mut module = Module::new();
    module.section(&types);
    module.section(&functions);
    module.section(&memory);
    module.section(&globals);
    module.section(&exports);
    module.section(&code);
    if !spec.data.is_empty() {
        module.section(&data);
    }
    module.finish()
}

/// Small instruction-buffer assembler: locals are appended on demand and
/// the finished body is handed to `FuncSpec`.
struct Asm {
    n_params: u32,
    locals: Vec<ValType>,
    ins: Vec<I<'static>>,
}

impl Asm {
    fn new(n_params: u32) -> Self {
        Asm {
            n_params,
            locals: Vec::new(),
            ins: Vec::new(),
        }
    }

    fn local(&mut self, ty: ValType) -> u32 {
        let index = self.n_params + self.locals.len() as u32;
        self.locals.push(ty);
        index
    }

    fn i(&mut self, instruction: I<'static>) {
        self.ins.push(instruction);
    }

    fn extend(&mut self, instructions: impl IntoIterator<Item = I<'static>>) {
        self.ins.extend(instructions);
    }
}

fn memarg8(offset: u64) -> MemArg {
    MemArg {
        offset,
        align: 0,
        memory_index: 0,
    }
}

fn memarg64(offset: u64) -> MemArg {
    MemArg {
        offset,
        align: 3,
        memory_index: 0,
    }
}

// ── json-v1 fixture modules (echo / fibonacci / fanout) ─────────────
//
// Function index layout in every json module:
//   0 = gnosis_alloc, 1 = main, 2 = gnosis_result_len, 3 = gnosis_free
// Globals: 0 = heap pointer (i32), 1 = result length (i32),
//          2 = fuel (i64, fibonacci only).
const JSON_FN_ALLOC: u32 = 0;
const JSON_GLOBAL_HEAP: u32 = 0;
const JSON_GLOBAL_RESULT_LEN: u32 = 1;
const JSON_GLOBAL_FUEL: u32 = 2;

fn json_alloc_func() -> FuncSpec {
    let mut a = Asm::new(1); // param 0: len (i32)
    let ptr = a.local(ValType::I32);
    let end = a.local(ValType::I32);
    let grow = a.local(ValType::I32);

    // ptr = (heap + 7) & ~7
    a.extend([
        I::GlobalGet(JSON_GLOBAL_HEAP),
        I::I32Const(7),
        I::I32Add,
        I::I32Const(-8),
        I::I32And,
        I::LocalSet(ptr),
        // end = ptr + len
        I::LocalGet(ptr),
        I::LocalGet(0),
        I::I32Add,
        I::LocalSet(end),
        // grow = ((end + 65535) >>> 16) - memory.size
        I::LocalGet(end),
        I::I32Const(65535),
        I::I32Add,
        I::I32Const(16),
        I::I32ShrU,
        I::MemorySize(0),
        I::I32Sub,
        I::LocalTee(grow),
        I::I32Const(0),
        I::I32GtS,
        I::If(BlockType::Empty),
        I::LocalGet(grow),
        I::MemoryGrow(0),
        I::I32Const(-1),
        I::I32Eq,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::End,
        // heap = end; return ptr
        I::LocalGet(end),
        I::GlobalSet(JSON_GLOBAL_HEAP),
        I::LocalGet(ptr),
    ]);

    FuncSpec {
        params: vec![ValType::I32],
        results: vec![ValType::I32],
        locals: a.locals,
        ins: a.ins,
    }
}

fn json_result_len_func() -> FuncSpec {
    FuncSpec {
        params: vec![],
        results: vec![ValType::I32],
        locals: vec![],
        ins: vec![I::GlobalGet(JSON_GLOBAL_RESULT_LEN)],
    }
}

fn json_free_func() -> FuncSpec {
    FuncSpec {
        params: vec![ValType::I32, ValType::I32],
        results: vec![],
        locals: vec![],
        ins: vec![],
    }
}

/// Emit: scan input bytes `[ptr, ptr+len)` for the exact needle (an
/// unrolled byte comparison — needles are short JSON keys), leaving
/// `cursor` local pointing just past the needle. Traps when absent.
fn emit_find_needle(a: &mut Asm, needle: &[u8], ptr: u32, limit: u32, cursor: u32) {
    // cursor = ptr
    a.extend([I::LocalGet(ptr), I::LocalSet(cursor)]);
    a.i(I::Block(BlockType::Empty)); // $found
    a.i(I::Loop(BlockType::Empty)); // $scan
                                    // if cursor + needle.len() > limit → decline (needle absent)
    a.extend([
        I::LocalGet(cursor),
        I::I32Const(needle.len() as i32),
        I::I32Add,
        I::LocalGet(limit),
        I::I32GtS,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
    ]);
    // unrolled compare
    for (offset, byte) in needle.iter().enumerate() {
        a.extend([
            I::LocalGet(cursor),
            I::I32Load8U(memarg8(offset as u64)),
            I::I32Const(*byte as i32),
            I::I32Eq,
        ]);
        if offset > 0 {
            a.i(I::I32And);
        }
    }
    a.i(I::BrIf(1)); // → $found
    a.extend([
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
        I::Br(0),
    ]);
    a.i(I::End); // $scan
    a.i(I::End); // $found
                 // cursor points at the needle start; advance past it.
    a.extend([
        I::LocalGet(cursor),
        I::I32Const(needle.len() as i32),
        I::I32Add,
        I::LocalSet(cursor),
    ]);
}

/// Emit: advance `cursor` to just past the ':' following a matched key,
/// then past any JSON whitespace. Traps on running off the input.
fn emit_skip_colon_ws(a: &mut Asm, limit: u32, cursor: u32, ch: u32) {
    // to the colon
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    emit_bounds_or_trap(a, cursor, limit);
    a.extend([
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::I32Const(b':' as i32),
        I::I32Eq,
        I::BrIf(1),
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.extend([
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
    ]);
    // past whitespace
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    emit_bounds_or_trap(a, cursor, limit);
    a.extend([
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::LocalTee(ch),
        I::I32Const(b' ' as i32),
        I::I32Eq,
        I::LocalGet(ch),
        I::I32Const(b'\t' as i32),
        I::I32Eq,
        I::I32Or,
        I::LocalGet(ch),
        I::I32Const(b'\n' as i32),
        I::I32Eq,
        I::I32Or,
        I::LocalGet(ch),
        I::I32Const(b'\r' as i32),
        I::I32Eq,
        I::I32Or,
        I::I32Eqz,
        I::BrIf(1),
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
}

fn emit_bounds_or_trap(a: &mut Asm, cursor: u32, limit: u32) {
    a.extend([
        I::LocalGet(cursor),
        I::LocalGet(limit),
        I::I32GeS,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
    ]);
}

/// Emit: read an unescaped JSON string value at `cursor` (must start
/// with '"'), leaving `vstart`/`vlen` locals set and `cursor` past the
/// closing quote. Any backslash escape or control byte DECLINES (trap):
/// the walker handles decoding there, and raw bytes copied verbatim are
/// only correct when no escape is present.
fn emit_read_string_value(a: &mut Asm, limit: u32, cursor: u32, ch: u32, vstart: u32, vlen: u32) {
    a.extend([
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::I32Const(b'"' as i32),
        I::I32Ne,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalTee(cursor),
        I::LocalSet(vstart),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    emit_bounds_or_trap(a, cursor, limit);
    a.extend([
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::LocalTee(ch),
        I::I32Const(b'"' as i32),
        I::I32Eq,
        I::BrIf(1),
        // backslash or control byte → decline
        I::LocalGet(ch),
        I::I32Const(b'\\' as i32),
        I::I32Eq,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(ch),
        I::I32Const(0x20),
        I::I32LtU,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.extend([
        I::LocalGet(cursor),
        I::LocalGet(vstart),
        I::I32Sub,
        I::LocalSet(vlen),
    ]);
}

fn emit_echo_module() -> Vec<u8> {
    // data: "hello:" literal at DATA_BASE
    let hello = b"hello:".to_vec();

    let mut a = Asm::new(2); // params: ptr, len
    let ptr = 0u32;
    let len = 1u32;
    let limit = a.local(ValType::I32);
    let cursor = a.local(ValType::I32);
    let ch = a.local(ValType::I32);
    let vstart = a.local(ValType::I32);
    let vlen = a.local(ValType::I32);
    let out = a.local(ValType::I32);
    let total = a.local(ValType::I32);

    a.extend([
        I::LocalGet(ptr),
        I::LocalGet(len),
        I::I32Add,
        I::LocalSet(limit),
    ]);
    emit_find_needle(&mut a, b"\"name\"", ptr, limit, cursor);
    emit_skip_colon_ws(&mut a, limit, cursor, ch);
    emit_read_string_value(&mut a, limit, cursor, ch, vstart, vlen);

    // total = 1 + 6 + vlen + 1 ; out = gnosis_alloc(total)
    a.extend([
        I::LocalGet(vlen),
        I::I32Const(8),
        I::I32Add,
        I::LocalTee(total),
        I::Call(JSON_FN_ALLOC),
        I::LocalSet(out),
        // out[0] = '"'
        I::LocalGet(out),
        I::I32Const(b'"' as i32),
        I::I32Store8(memarg8(0)),
        // copy "hello:" → out+1
        I::LocalGet(out),
        I::I32Const(1),
        I::I32Add,
        I::I32Const(DATA_BASE as i32),
        I::I32Const(hello.len() as i32),
        I::MemoryCopy {
            src_mem: 0,
            dst_mem: 0,
        },
        // copy value → out+7
        I::LocalGet(out),
        I::I32Const(7),
        I::I32Add,
        I::LocalGet(vstart),
        I::LocalGet(vlen),
        I::MemoryCopy {
            src_mem: 0,
            dst_mem: 0,
        },
        // out[7 + vlen] = '"'
        I::LocalGet(out),
        I::I32Const(7),
        I::I32Add,
        I::LocalGet(vlen),
        I::I32Add,
        I::I32Const(b'"' as i32),
        I::I32Store8(memarg8(0)),
        I::LocalGet(total),
        I::GlobalSet(JSON_GLOBAL_RESULT_LEN),
        I::LocalGet(out),
    ]);

    let main = FuncSpec {
        params: vec![ValType::I32, ValType::I32],
        results: vec![ValType::I32],
        locals: a.locals,
        ins: a.ins,
    };

    assemble(&ModuleSpec {
        pages_min: 2,
        globals: vec![GlobalInit::I32(HEAP_BASE), GlobalInit::I32(0)],
        data: vec![(DATA_BASE, hello)],
        funcs: vec![
            json_alloc_func(),
            main,
            json_result_len_func(),
            json_free_func(),
        ],
        func_exports: vec![
            ("gnosis_alloc", 0),
            ("main", 1),
            ("gnosis_result_len", 2),
            ("gnosis_free", 3),
        ],
    })
}

fn emit_fanout_module() -> Vec<u8> {
    // data: ":user|" at DATA_BASE, ":profile" at DATA_BASE + 8
    let seg_user = b":user|".to_vec();
    let seg_profile = b":profile".to_vec();
    let user_off = DATA_BASE;
    let profile_off = DATA_BASE + 8;

    let mut a = Asm::new(2);
    let ptr = 0u32;
    let len = 1u32;
    let limit = a.local(ValType::I32);
    let cursor = a.local(ValType::I32);
    let ch = a.local(ValType::I32);
    let vstart = a.local(ValType::I32);
    let vlen = a.local(ValType::I32);
    let out = a.local(ValType::I32);
    let total = a.local(ValType::I32);
    let write = a.local(ValType::I32);

    a.extend([
        I::LocalGet(ptr),
        I::LocalGet(len),
        I::I32Add,
        I::LocalSet(limit),
    ]);
    emit_find_needle(&mut a, b"\"userId\"", ptr, limit, cursor);
    emit_skip_colon_ws(&mut a, limit, cursor, ch);
    emit_read_string_value(&mut a, limit, cursor, ch, vstart, vlen);

    // total = 2*vlen + 16 ('"' + v + ":user|" + v + ":profile" + '"')
    a.extend([
        I::LocalGet(vlen),
        I::I32Const(1),
        I::I32Shl,
        I::I32Const(16),
        I::I32Add,
        I::LocalTee(total),
        I::Call(JSON_FN_ALLOC),
        I::LocalTee(out),
        I::LocalSet(write),
        // '"'
        I::LocalGet(write),
        I::I32Const(b'"' as i32),
        I::I32Store8(memarg8(0)),
        I::LocalGet(write),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(write),
        // value
        I::LocalGet(write),
        I::LocalGet(vstart),
        I::LocalGet(vlen),
        I::MemoryCopy {
            src_mem: 0,
            dst_mem: 0,
        },
        I::LocalGet(write),
        I::LocalGet(vlen),
        I::I32Add,
        I::LocalSet(write),
        // ":user|"
        I::LocalGet(write),
        I::I32Const(user_off as i32),
        I::I32Const(seg_user.len() as i32),
        I::MemoryCopy {
            src_mem: 0,
            dst_mem: 0,
        },
        I::LocalGet(write),
        I::I32Const(seg_user.len() as i32),
        I::I32Add,
        I::LocalSet(write),
        // value again
        I::LocalGet(write),
        I::LocalGet(vstart),
        I::LocalGet(vlen),
        I::MemoryCopy {
            src_mem: 0,
            dst_mem: 0,
        },
        I::LocalGet(write),
        I::LocalGet(vlen),
        I::I32Add,
        I::LocalSet(write),
        // ":profile"
        I::LocalGet(write),
        I::I32Const(profile_off as i32),
        I::I32Const(seg_profile.len() as i32),
        I::MemoryCopy {
            src_mem: 0,
            dst_mem: 0,
        },
        I::LocalGet(write),
        I::I32Const(seg_profile.len() as i32),
        I::I32Add,
        I::LocalSet(write),
        // closing '"'
        I::LocalGet(write),
        I::I32Const(b'"' as i32),
        I::I32Store8(memarg8(0)),
        I::LocalGet(total),
        I::GlobalSet(JSON_GLOBAL_RESULT_LEN),
        I::LocalGet(out),
    ]);

    let main = FuncSpec {
        params: vec![ValType::I32, ValType::I32],
        results: vec![ValType::I32],
        locals: a.locals,
        ins: a.ins,
    };

    assemble(&ModuleSpec {
        pages_min: 2,
        globals: vec![GlobalInit::I32(HEAP_BASE), GlobalInit::I32(0)],
        data: vec![(user_off, seg_user), (profile_off, seg_profile)],
        funcs: vec![
            json_alloc_func(),
            main,
            json_result_len_func(),
            json_free_func(),
        ],
        func_exports: vec![
            ("gnosis_alloc", 0),
            ("main", 1),
            ("gnosis_result_len", 2),
            ("gnosis_free", 3),
        ],
    })
}

fn emit_fibonacci_module() -> Vec<u8> {
    let mut a = Asm::new(2);
    let ptr = 0u32;
    let len = 1u32;
    let limit = a.local(ValType::I32);
    let cursor = a.local(ValType::I32);
    let ch = a.local(ValType::I32);
    let n = a.local(ValType::F64);
    let prev = a.local(ValType::F64);
    let cur = a.local(ValType::F64);
    let idx = a.local(ValType::F64);
    let result = a.local(ValType::F64);
    let v = a.local(ValType::I64);
    let digits = a.local(ValType::I32);
    let t = a.local(ValType::I32);
    let out = a.local(ValType::I32);

    a.extend([
        I::LocalGet(ptr),
        I::LocalGet(len),
        I::I32Add,
        I::LocalSet(limit),
    ]);
    emit_find_needle(&mut a, b"\"n\"", ptr, limit, cursor);
    emit_skip_colon_ws(&mut a, limit, cursor, ch);

    // Parse the number. The walker clamps negatives to 0 (the C lane
    // does the same); a '-' therefore swallows its digits and yields 0.
    // Anything non-integral (a '.', exponent, or bare non-digit)
    // DECLINES — strtod's float acceptance stays walker jurisdiction.
    a.extend([
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::I32Const(b'-' as i32),
        I::I32Eq,
        I::If(BlockType::Empty),
        // skip '-' and all digits; n stays 0
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
    ]);
    // digit-skip loop (inside the If)
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::LocalGet(cursor),
        I::LocalGet(limit),
        I::I32GeS,
        I::BrIf(1),
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::LocalTee(ch),
        I::I32Const(b'0' as i32),
        I::I32LtU,
        I::BrIf(1),
        I::LocalGet(ch),
        I::I32Const(b'9' as i32),
        I::I32GtU,
        I::BrIf(1),
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.i(I::Else);
    // must start with a digit
    a.extend([
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::LocalTee(ch),
        I::I32Const(b'0' as i32),
        I::I32LtU,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(ch),
        I::I32Const(b'9' as i32),
        I::I32GtU,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
    ]);
    // accumulate digits into n (f64; exact while n < 2^32 by the fence)
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::LocalGet(cursor),
        I::LocalGet(limit),
        I::I32GeS,
        I::BrIf(1),
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::LocalTee(ch),
        I::I32Const(b'0' as i32),
        I::I32LtU,
        I::BrIf(1),
        I::LocalGet(ch),
        I::I32Const(b'9' as i32),
        I::I32GtU,
        I::BrIf(1),
        I::LocalGet(n),
        I::F64Const(10.0.into()),
        I::F64Mul,
        I::LocalGet(ch),
        I::I32Const(b'0' as i32),
        I::I32Sub,
        I::F64ConvertI32U,
        I::F64Add,
        I::LocalTee(n),
        I::F64Const(4294967296.0.into()),
        I::F64Ge,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(cursor),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(cursor),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    // a trailing '.', 'e', or 'E' means a float literal → decline
    a.extend([
        I::LocalGet(cursor),
        I::LocalGet(limit),
        I::I32LtS,
        I::If(BlockType::Empty),
        I::LocalGet(cursor),
        I::I32Load8U(memarg8(0)),
        I::LocalTee(ch),
        I::I32Const(b'.' as i32),
        I::I32Eq,
        I::LocalGet(ch),
        I::I32Const(b'e' as i32),
        I::I32Eq,
        I::I32Or,
        I::LocalGet(ch),
        I::I32Const(b'E' as i32),
        I::I32Eq,
        I::I32Or,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::End,
    ]);
    a.i(I::End); // close the '-' If/Else

    // fibonacci in f64 — the walker's own arithmetic. n < 2 → n.
    a.extend([
        I::LocalGet(n),
        I::F64Const(2.0.into()),
        I::F64Lt,
        I::If(BlockType::Empty),
        I::LocalGet(n),
        I::LocalSet(result),
        I::Else,
        I::F64Const(0.0.into()),
        I::LocalSet(prev),
        I::F64Const(1.0.into()),
        I::LocalSet(cur),
        I::F64Const(2.0.into()),
        I::LocalSet(idx),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::LocalGet(idx),
        I::LocalGet(n),
        I::F64Gt,
        I::BrIf(1),
        // fuel
        I::GlobalGet(JSON_GLOBAL_FUEL),
        I::I64Eqz,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::GlobalGet(JSON_GLOBAL_FUEL),
        I::I64Const(1),
        I::I64Sub,
        I::GlobalSet(JSON_GLOBAL_FUEL),
        // next = prev + cur; prev = cur; cur = next
        I::LocalGet(prev),
        I::LocalGet(cur),
        I::F64Add,
        I::LocalGet(cur),
        I::LocalSet(prev),
        I::LocalSet(cur),
        I::LocalGet(idx),
        I::F64Const(1.0.into()),
        I::F64Add,
        I::LocalSet(idx),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.extend([I::LocalGet(cur), I::LocalSet(result), I::End]);

    // Answer only integral results in the 2^53-exact range (the aot_c
    // main() guard); everything else declines to the walker.
    a.extend([
        I::LocalGet(result),
        I::LocalGet(result),
        I::F64Trunc,
        I::F64Ne,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(result),
        I::F64Abs,
        I::F64Const(9007199254740992.0.into()),
        I::F64Gt,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        I::LocalGet(result),
        I::F64Const(0.0.into()),
        I::F64Lt,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        // v = (i64) result; format decimal digits into SCRATCH reversed
        I::LocalGet(result),
        I::I64TruncSatF64S,
        I::LocalSet(v),
        I::I32Const(0),
        I::LocalSet(digits),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        // scratch[digits] = '0' + v % 10
        I::I32Const(SCRATCH_BASE as i32),
        I::LocalGet(digits),
        I::I32Add,
        I::LocalGet(v),
        I::I64Const(10),
        I::I64RemU,
        I::I32WrapI64,
        I::I32Const(b'0' as i32),
        I::I32Add,
        I::I32Store8(memarg8(0)),
        I::LocalGet(digits),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(digits),
        I::LocalGet(v),
        I::I64Const(10),
        I::I64DivU,
        I::LocalTee(v),
        I::I64Eqz,
        I::BrIf(1),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    // out = alloc(digits); copy reversed
    a.extend([
        I::LocalGet(digits),
        I::Call(JSON_FN_ALLOC),
        I::LocalSet(out),
        I::I32Const(0),
        I::LocalSet(t),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::LocalGet(t),
        I::LocalGet(digits),
        I::I32GeS,
        I::BrIf(1),
        // out[t] = scratch[digits - 1 - t]
        I::LocalGet(out),
        I::LocalGet(t),
        I::I32Add,
        I::I32Const(SCRATCH_BASE as i32),
        I::LocalGet(digits),
        I::I32Add,
        I::I32Const(1),
        I::I32Sub,
        I::LocalGet(t),
        I::I32Sub,
        I::I32Load8U(memarg8(0)),
        I::I32Store8(memarg8(0)),
        I::LocalGet(t),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(t),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.extend([
        I::LocalGet(digits),
        I::GlobalSet(JSON_GLOBAL_RESULT_LEN),
        I::LocalGet(out),
    ]);

    let main = FuncSpec {
        params: vec![ValType::I32, ValType::I32],
        results: vec![ValType::I32],
        locals: a.locals,
        ins: a.ins,
    };

    assemble(&ModuleSpec {
        pages_min: 2,
        globals: vec![
            GlobalInit::I32(HEAP_BASE),
            GlobalInit::I32(0),
            GlobalInit::I64(FUEL_INIT),
        ],
        data: vec![],
        funcs: vec![
            json_alloc_func(),
            main,
            json_result_len_func(),
            json_free_func(),
        ],
        func_exports: vec![
            ("gnosis_alloc", 0),
            ("main", 1),
            ("gnosis_result_len", 2),
            ("gnosis_free", 3),
        ],
    })
}

// ── Certified numeric-loop emitter (scalar-v1) ──────────────────────
//
// The wasm twin of aot_c::numeric_loop_c: a single exported TS/JS
// function over f64 scalars — let/const, arithmetic/comparison
// expressions, C-style `for`/`while`, `if`/`else`, fixed-size local
// arrays, acyclic helper calls, exactly-representable Math intrinsics.
// Everything compiles to f64 semantics IDENTICAL to the walker's; the
// module refuses (None) on any construct outside the class and traps
// (decline) at runtime on any input where its answer could diverge.
//
// Divergence-elimination notes, mirroring the walker (Rust) rather than
// the C lane where the two differ:
// - Bitwise family: `i64.trunc_sat_f64_s` IS Rust's saturating `as`
//   cast (NaN → 0), and `f64.convert_i64_s` IS Rust's `as f64`, so
//   `&, |, ^, <<, >>` answer on the FULL walker domain — no 2^32
//   fence, no exactness decline. `>>>` uses `i32.trunc_sat_f64_u`,
//   Rust's saturating u32 cast.
// - `%` answers only on integral operands with |x| < 2^32 (exact i64
//   remainder, dividend-sign zero preserved); everything else traps.
//   Real fmod bit-parity in hand-emitted wasm is not worth the risk.
// - Math.round is half-away-from-zero (Rust `f64::round`), built from
//   trunc + exact fraction compare — NOT wasm `f64.nearest` (that is
//   round-half-even and would diverge at *.5).
// - Math.min/max are NaN-IGNORING (Rust semantics) — NOT wasm
//   `f64.min/max` (NaN-propagating), hence the helper wrappers.
// - Implicit JS `undefined` (falling off the end) traps: f64 cannot
//   represent it, and a synthetic NaN could launder through a
//   comparison into a wrong answer.

const HELPER_MOD: u32 = 0;
const HELPER_ROUND: u32 = 1;
const HELPER_MIN: u32 = 2;
const HELPER_MAX: u32 = 3;
const HELPER_ARR_ADDR: u32 = 4;
const HELPER_COUNT: u32 = 5;
const NUMERIC_GLOBAL_FUEL: u32 = 0;

struct NumericModule {
    bytes: Vec<u8>,
    pages: u64,
}

fn helper_js_mod() -> FuncSpec {
    let mut a = Asm::new(2); // a, b : f64
    let ia = a.local(ValType::I64);
    let rem = a.local(ValType::I64);
    let nan: I<'static> = I::F64Const(f64::NAN.into());

    // NaN operands → NaN (JS x % NaN, NaN % y)
    a.extend([
        I::LocalGet(0),
        I::LocalGet(0),
        I::F64Ne,
        I::If(BlockType::Empty),
        nan.clone(),
        I::Return,
        I::End,
        I::LocalGet(1),
        I::LocalGet(1),
        I::F64Ne,
        I::If(BlockType::Empty),
        nan.clone(),
        I::Return,
        I::End,
        // b == 0 (covers -0) → NaN
        I::LocalGet(1),
        I::F64Const(0.0.into()),
        I::F64Eq,
        I::If(BlockType::Empty),
        nan,
        I::Return,
        I::End,
    ]);
    // integral + |x| < 2^32 fences (else decline)
    for operand in [0u32, 1u32] {
        a.extend([
            I::LocalGet(operand),
            I::LocalGet(operand),
            I::F64Trunc,
            I::F64Ne,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
            I::LocalGet(operand),
            I::F64Abs,
            I::F64Const(4294967296.0.into()),
            I::F64Ge,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
        ]);
    }
    a.extend([
        I::LocalGet(0),
        I::I64TruncSatF64S,
        I::LocalTee(ia),
        I::LocalGet(1),
        I::I64TruncSatF64S,
        I::I64RemS,
        I::LocalSet(rem),
        // r == 0 && a < 0 → -0.0 (dividend-sign zero)
        I::LocalGet(rem),
        I::I64Eqz,
        I::LocalGet(0),
        I::F64Const(0.0.into()),
        I::F64Lt,
        I::I32And,
        I::If(BlockType::Result(ValType::F64)),
        I::F64Const((-0.0f64).into()),
        I::Else,
        I::LocalGet(rem),
        I::F64ConvertI64S,
        I::End,
    ]);

    FuncSpec {
        params: vec![ValType::F64, ValType::F64],
        results: vec![ValType::F64],
        locals: a.locals,
        ins: a.ins,
    }
}

fn helper_js_round() -> FuncSpec {
    let mut a = Asm::new(1);
    let r = a.local(ValType::F64);
    let f = a.local(ValType::F64);
    a.extend([
        // NaN → itself
        I::LocalGet(0),
        I::LocalGet(0),
        I::F64Ne,
        I::If(BlockType::Empty),
        I::LocalGet(0),
        I::Return,
        I::End,
        I::LocalGet(0),
        I::F64Trunc,
        I::LocalSet(r),
        I::LocalGet(0),
        I::LocalGet(r),
        I::F64Sub,
        I::LocalSet(f),
        // f >= 0.5 → r + 1 (half away from zero, Rust f64::round)
        I::LocalGet(f),
        I::F64Const(0.5.into()),
        I::F64Ge,
        I::If(BlockType::Empty),
        I::LocalGet(r),
        I::F64Const(1.0.into()),
        I::F64Add,
        I::Return,
        I::End,
        I::LocalGet(f),
        I::F64Const((-0.5f64).into()),
        I::F64Le,
        I::If(BlockType::Empty),
        I::LocalGet(r),
        I::F64Const(1.0.into()),
        I::F64Sub,
        I::Return,
        I::End,
        I::LocalGet(r),
    ]);
    FuncSpec {
        params: vec![ValType::F64],
        results: vec![ValType::F64],
        locals: a.locals,
        ins: a.ins,
    }
}

fn helper_js_min_max(is_min: bool) -> FuncSpec {
    let mut a = Asm::new(2);
    a.extend([
        // NaN-ignoring fold (Rust f64::min/max): NaN yields the other.
        I::LocalGet(0),
        I::LocalGet(0),
        I::F64Ne,
        I::If(BlockType::Empty),
        I::LocalGet(1),
        I::Return,
        I::End,
        I::LocalGet(1),
        I::LocalGet(1),
        I::F64Ne,
        I::If(BlockType::Empty),
        I::LocalGet(0),
        I::Return,
        I::End,
        I::LocalGet(0),
        I::LocalGet(1),
        if is_min { I::F64Min } else { I::F64Max },
    ]);
    FuncSpec {
        params: vec![ValType::F64, ValType::F64],
        results: vec![ValType::F64],
        locals: a.locals,
        ins: a.ins,
    }
}

/// (base: i32, len: i32, idx: f64) -> i32 byte address. Traps on
/// non-integral, negative, or out-of-bounds indexes — the walker reads
/// `undefined` there, so the wasm lane never answers.
fn helper_arr_addr() -> FuncSpec {
    let mut a = Asm::new(3);
    a.extend([
        // idx != trunc(idx) (also catches NaN) → decline
        I::LocalGet(2),
        I::LocalGet(2),
        I::F64Trunc,
        I::F64Ne,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        // idx < 0 → decline
        I::LocalGet(2),
        I::F64Const(0.0.into()),
        I::F64Lt,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        // idx >= len → decline
        I::LocalGet(2),
        I::LocalGet(1),
        I::F64ConvertI32S,
        I::F64Ge,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        // base + (i32) idx * 8
        I::LocalGet(0),
        I::LocalGet(2),
        I::I32TruncSatF64U,
        I::I32Const(8),
        I::I32Mul,
        I::I32Add,
    ]);
    FuncSpec {
        params: vec![ValType::I32, ValType::I32, ValType::F64],
        results: vec![ValType::I32],
        locals: a.locals,
        ins: a.ins,
    }
}

#[derive(Clone)]
struct WasmFnDecl<'t> {
    params: Vec<String>,
    body: tree_sitter::Node<'t>,
}

#[derive(Debug, Clone, Copy, PartialEq)]
enum Slot {
    Scalar(u32),
    Array { base: u32, len: usize },
}

struct NumericWasmEmitter<'s, 't> {
    source: &'s str,
    funcs: HashMap<String, WasmFnDecl<'t>>,
    scopes: Vec<HashMap<String, Slot>>,
    asm: Asm,
    /// Finished (name, spec) pairs in wasm index order (after helpers).
    finished: Vec<(String, FuncSpec)>,
    indices: HashMap<String, u32>,
    done: HashSet<String>,
    in_progress: HashSet<String>,
    next_array_offset: u32,
}

/// Direct entry to the certified numeric-loop class: core module bytes
/// (no manifest section), or None when the program is outside the
/// class. This is the wasm twin of `aot_c::numeric_loop_c` and the
/// surface the parity harness drives.
pub fn numeric_loop_wasm_bytes(source: &str, export_name: &str) -> Option<Vec<u8>> {
    numeric_loop_wasm(source, export_name).map(|module| module.bytes)
}

fn numeric_loop_wasm(source: &str, export_name: &str) -> Option<NumericModule> {
    let mut parser = tree_sitter::Parser::new();
    parser
        .set_language(&tree_sitter_typescript::LANGUAGE_TYPESCRIPT.into())
        .ok()?;
    let tree = parser.parse(source, None)?;

    let mut funcs: HashMap<String, WasmFnDecl> = HashMap::new();
    let mut stack = vec![tree.root_node()];
    while let Some(node) = stack.pop() {
        if node.kind() == "function_declaration" {
            let name_node = node.child_by_field_name("name")?;
            let name = js_ident(wasm_node_text(name_node, source))?;
            let params_node = node.child_by_field_name("parameters")?;
            let mut params: Vec<String> = Vec::new();
            let mut walker = params_node.walk();
            for param in params_node.named_children(&mut walker) {
                let pattern = match param.kind() {
                    "required_parameter" => param.child_by_field_name("pattern")?,
                    "identifier" => param,
                    "comment" => continue,
                    _ => return None,
                };
                if pattern.kind() != "identifier" {
                    return None;
                }
                params.push(js_ident(wasm_node_text(pattern, source))?);
            }
            let body = node.child_by_field_name("body")?;
            funcs.insert(name, WasmFnDecl { params, body });
        }
        let mut walker = node.walk();
        for child in node.named_children(&mut walker) {
            stack.push(child);
        }
    }

    let entry = funcs.get(export_name)?;
    if entry.params.len() > 1 {
        // scalar-v1 carries a single numeric input.
        return None;
    }
    let entry_arity = entry.params.len();

    let mut emitter = NumericWasmEmitter {
        source,
        funcs,
        scopes: Vec::new(),
        asm: Asm::new(0),
        finished: Vec::new(),
        indices: HashMap::new(),
        done: HashSet::new(),
        in_progress: HashSet::new(),
        next_array_offset: ARRAY_BASE,
    };
    emitter.compile_function(export_name)?;

    let entry_index = *emitter.indices.get(export_name)?;
    let array_bytes = emitter.next_array_offset as u64;
    let pages = array_bytes.div_ceil(WASM_PAGE).max(1);

    let mut funcs_out = vec![
        helper_js_mod(),
        helper_js_round(),
        helper_js_min_max(true),
        helper_js_min_max(false),
        helper_arr_addr(),
    ];
    for (_, spec) in emitter.finished {
        funcs_out.push(spec);
    }
    debug_assert_eq!(entry_arity, funcs_out[entry_index as usize].params.len());

    let bytes = assemble(&ModuleSpec {
        pages_min: pages,
        globals: vec![GlobalInit::I64(FUEL_INIT)],
        data: vec![],
        funcs: funcs_out,
        func_exports: vec![("main", entry_index)],
    });
    Some(NumericModule { bytes, pages })
}

fn wasm_node_text<'s>(node: tree_sitter::Node, source: &'s str) -> &'s str {
    source.get(node.start_byte()..node.end_byte()).unwrap_or("")
}

/// Identifier validation, same acceptance as aot_c::c_ident so the two
/// certified classes stay aligned.
fn js_ident(name: &str) -> Option<String> {
    let mut bytes = name.bytes();
    let first = bytes.next()?;
    if !(first.is_ascii_alphabetic() || first == b'_') {
        return None;
    }
    if !bytes.all(|b| b.is_ascii_alphanumeric() || b == b'_') {
        return None;
    }
    Some(name.to_string())
}

/// JS numeric literal → f64, refusing anything whose f64 value is not
/// unambiguous (BigInt suffix, legacy octal).
fn parse_js_number(text: &str) -> Option<f64> {
    let cleaned: String = text.chars().filter(|&c| c != '_').collect();
    if cleaned.ends_with('n') {
        return None; // BigInt: outside f64 semantics.
    }
    if let Some(hex) = cleaned
        .strip_prefix("0x")
        .or_else(|| cleaned.strip_prefix("0X"))
    {
        return u128::from_str_radix(hex, 16).ok().map(|v| v as f64);
    }
    if let Some(oct) = cleaned
        .strip_prefix("0o")
        .or_else(|| cleaned.strip_prefix("0O"))
    {
        return u128::from_str_radix(oct, 8).ok().map(|v| v as f64);
    }
    if let Some(bin) = cleaned
        .strip_prefix("0b")
        .or_else(|| cleaned.strip_prefix("0B"))
    {
        return u128::from_str_radix(bin, 2).ok().map(|v| v as f64);
    }
    // Legacy sloppy-mode octal ("0755") diverges between JS engines and
    // a plain f64 parse — refuse the whole shape.
    if cleaned.len() > 1 && cleaned.starts_with('0') && cleaned.as_bytes()[1].is_ascii_digit() {
        return None;
    }
    cleaned.parse::<f64>().ok()
}

fn strip_parens_ts(node: tree_sitter::Node) -> tree_sitter::Node {
    if node.kind() == "parenthesized_expression" {
        if let Some(inner) = node.named_child(0) {
            return inner;
        }
    }
    node
}

impl<'s, 't> NumericWasmEmitter<'s, 't> {
    fn text(&self, node: tree_sitter::Node) -> &'s str {
        wasm_node_text(node, self.source)
    }

    fn slot(&self, name: &str) -> Option<Slot> {
        self.scopes
            .iter()
            .rev()
            .find_map(|scope| scope.get(name).copied())
    }

    fn declared(&self, name: &str) -> bool {
        self.slot(name).is_some()
    }

    fn fuel_check(&mut self) {
        self.asm.extend([
            I::GlobalGet(NUMERIC_GLOBAL_FUEL),
            I::I64Eqz,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
            I::GlobalGet(NUMERIC_GLOBAL_FUEL),
            I::I64Const(1),
            I::I64Sub,
            I::GlobalSet(NUMERIC_GLOBAL_FUEL),
        ]);
    }

    /// Value on stack (f64) → truthy i32, JS semantics (NaN and 0 are
    /// falsy; everything else truthy).
    fn emit_truthy(&mut self) {
        let tmp = self.asm.local(ValType::F64);
        self.asm.extend([
            I::LocalTee(tmp),
            I::LocalGet(tmp),
            I::F64Eq,
            I::LocalGet(tmp),
            I::F64Const(0.0.into()),
            I::F64Ne,
            I::I32And,
        ]);
    }

    fn compile_function(&mut self, name: &str) -> Option<()> {
        if self.done.contains(name) {
            return Some(());
        }
        if self.in_progress.contains(name) {
            // Recursion — the walker + admission gate's jurisdiction.
            return None;
        }
        let decl = self.funcs.get(name)?.clone();
        self.in_progress.insert(name.to_string());

        let saved_scopes = std::mem::take(&mut self.scopes);
        let saved_asm = std::mem::replace(&mut self.asm, Asm::new(decl.params.len() as u32));
        self.scopes = vec![decl
            .params
            .iter()
            .enumerate()
            .map(|(index, param)| (param.clone(), Slot::Scalar(index as u32)))
            .collect()];

        self.statement_block(decl.body)?;
        // Falling off the end is JS `undefined` — decline immediately
        // (entry and helper alike): f64 cannot carry it, and a
        // synthetic NaN could launder into a wrong answer upstream.
        self.asm.i(I::Unreachable);

        let finished_asm = std::mem::replace(&mut self.asm, saved_asm);
        self.scopes = saved_scopes;

        let spec = FuncSpec {
            params: vec![ValType::F64; decl.params.len()],
            results: vec![ValType::F64],
            locals: finished_asm.locals,
            ins: finished_asm.ins,
        };
        let index = HELPER_COUNT + self.finished.len() as u32;
        self.finished.push((name.to_string(), spec));
        self.indices.insert(name.to_string(), index);
        self.in_progress.remove(name);
        self.done.insert(name.to_string());
        Some(())
    }

    fn statement_block(&mut self, block: tree_sitter::Node) -> Option<()> {
        self.scopes.push(HashMap::new());
        let mut walker = block.walk();
        for stmt in block.named_children(&mut walker) {
            self.statement(stmt)?;
        }
        self.scopes.pop();
        Some(())
    }

    fn statement(&mut self, stmt: tree_sitter::Node) -> Option<()> {
        match stmt.kind() {
            "comment" | "empty_statement" => Some(()),
            "lexical_declaration" | "variable_declaration" => {
                let mut walker = stmt.walk();
                for declarator in stmt.named_children(&mut walker) {
                    if declarator.kind() == "comment" {
                        continue;
                    }
                    if declarator.kind() != "variable_declarator" {
                        return None;
                    }
                    self.declarator(declarator)?;
                }
                Some(())
            }
            "expression_statement" => self.assignment_like(stmt.named_child(0)?),
            "return_statement" => {
                let value = stmt.named_child(0)?;
                self.expr(value)?;
                self.asm.i(I::Return);
                Some(())
            }
            "if_statement" => {
                let cond = stmt.child_by_field_name("condition")?;
                self.expr(strip_parens_ts(cond))?;
                self.emit_truthy();
                self.asm.i(I::If(BlockType::Empty));
                self.nested_statement(stmt.child_by_field_name("consequence")?)?;
                if let Some(alternative) = stmt.child_by_field_name("alternative") {
                    let else_stmt = alternative.named_child(0)?;
                    self.asm.i(I::Else);
                    self.nested_statement(else_stmt)?;
                }
                self.asm.i(I::End);
                Some(())
            }
            "while_statement" => {
                let cond = stmt.child_by_field_name("condition")?;
                self.asm.i(I::Block(BlockType::Empty));
                self.asm.i(I::Loop(BlockType::Empty));
                self.expr(strip_parens_ts(cond))?;
                self.emit_truthy();
                self.asm.extend([I::I32Eqz, I::BrIf(1)]);
                self.fuel_check();
                self.nested_statement(stmt.child_by_field_name("body")?)?;
                self.asm.extend([I::Br(0), I::End, I::End]);
                Some(())
            }
            "for_statement" => {
                self.scopes.push(HashMap::new());
                match stmt.child_by_field_name("initializer") {
                    None => {}
                    Some(init) => match init.kind() {
                        "lexical_declaration" | "variable_declaration" => {
                            let declarator = init.named_child(0)?;
                            if init.named_child_count() != 1
                                || declarator.kind() != "variable_declarator"
                            {
                                return None;
                            }
                            self.declarator(declarator)?;
                        }
                        "expression_statement" => {
                            self.assignment_like(init.named_child(0)?)?;
                        }
                        _ => {
                            self.assignment_like(init)?;
                        }
                    },
                }
                self.asm.i(I::Block(BlockType::Empty));
                self.asm.i(I::Loop(BlockType::Empty));
                match stmt.child_by_field_name("condition") {
                    None => {}
                    Some(cond) => {
                        let inner = if cond.kind() == "expression_statement" {
                            cond.named_child(0)?
                        } else {
                            cond
                        };
                        self.expr(strip_parens_ts(inner))?;
                        self.emit_truthy();
                        self.asm.extend([I::I32Eqz, I::BrIf(1)]);
                    }
                }
                self.fuel_check();
                self.nested_statement(stmt.child_by_field_name("body")?)?;
                if let Some(update) = stmt.child_by_field_name("increment") {
                    self.assignment_like(update)?;
                }
                self.asm.extend([I::Br(0), I::End, I::End]);
                self.scopes.pop();
                Some(())
            }
            "statement_block" => self.statement_block(stmt),
            _ => None,
        }
    }

    fn nested_statement(&mut self, stmt: tree_sitter::Node) -> Option<()> {
        if stmt.kind() == "statement_block" {
            self.statement_block(stmt)
        } else {
            self.statement(stmt)
        }
    }

    fn declarator(&mut self, declarator: tree_sitter::Node) -> Option<()> {
        let name_node = declarator.child_by_field_name("name")?;
        if name_node.kind() != "identifier" {
            return None;
        }
        let name = js_ident(self.text(name_node))?;
        if self.declared(&name) {
            // JS shadowing / re-declaration: outside the class.
            return None;
        }
        let value = declarator.child_by_field_name("value")?;
        if value.kind() == "array" {
            let mut elements: Vec<tree_sitter::Node> = Vec::new();
            let mut walker = value.walk();
            for element in value.named_children(&mut walker) {
                if element.kind() == "comment" {
                    continue;
                }
                elements.push(element);
            }
            if elements.is_empty() {
                // Zero-length arrays refuse in the C lane; keep the
                // class definitions identical.
                return None;
            }
            let len = elements.len();
            let base = self.next_array_offset;
            self.next_array_offset = self
                .next_array_offset
                .checked_add((len as u32).checked_mul(8)?)?;
            // Safe static placement: the call graph is acyclic, so a
            // function has at most one live frame and every array is
            // re-initialized at its declaration site on entry.
            self.scopes
                .last_mut()?
                .insert(name.clone(), Slot::Array { base, len });
            for (index, element) in elements.into_iter().enumerate() {
                self.asm.i(I::I32Const((base + (index as u32) * 8) as i32));
                self.expr(element)?;
                self.asm.i(I::F64Store(memarg64(0)));
            }
            Some(())
        } else {
            self.expr(value)?;
            let local = self.asm.local(ValType::F64);
            self.asm.i(I::LocalSet(local));
            self.scopes.last_mut()?.insert(name, Slot::Scalar(local));
            Some(())
        }
    }

    /// Assignment-shaped statements: `x = e`, `x op= e`, `x++/x--`,
    /// `a[i] = e`, `a[i] op= e`. Leaves the stack empty.
    fn assignment_like(&mut self, node: tree_sitter::Node) -> Option<()> {
        match node.kind() {
            "assignment_expression" => {
                let left = node.child_by_field_name("left")?;
                match left.kind() {
                    "identifier" => {
                        let name = js_ident(self.text(left))?;
                        let Some(Slot::Scalar(local)) = self.slot(&name) else {
                            return None;
                        };
                        self.expr(node.child_by_field_name("right")?)?;
                        self.asm.i(I::LocalSet(local));
                        Some(())
                    }
                    "subscript_expression" => {
                        self.emit_subscript_addr(left)?;
                        self.expr(node.child_by_field_name("right")?)?;
                        self.asm.i(I::F64Store(memarg64(0)));
                        Some(())
                    }
                    _ => None,
                }
            }
            "augmented_assignment_expression" => {
                let left = node.child_by_field_name("left")?;
                let op = node.child_by_field_name("operator").map(|n| self.text(n))?;
                match left.kind() {
                    "identifier" => {
                        let name = js_ident(self.text(left))?;
                        let Some(Slot::Scalar(local)) = self.slot(&name) else {
                            return None;
                        };
                        self.asm.i(I::LocalGet(local));
                        self.expr(node.child_by_field_name("right")?)?;
                        match op {
                            "+=" => self.asm.i(I::F64Add),
                            "-=" => self.asm.i(I::F64Sub),
                            "*=" => self.asm.i(I::F64Mul),
                            "/=" => self.asm.i(I::F64Div),
                            "%=" => self.asm.i(I::Call(HELPER_MOD)),
                            _ => return None,
                        }
                        self.asm.i(I::LocalSet(local));
                        Some(())
                    }
                    "subscript_expression" => {
                        let addr = self.asm.local(ValType::I32);
                        let value = self.asm.local(ValType::F64);
                        self.emit_subscript_addr(left)?;
                        self.asm
                            .extend([I::LocalTee(addr), I::F64Load(memarg64(0))]);
                        self.expr(node.child_by_field_name("right")?)?;
                        match op {
                            "+=" => self.asm.i(I::F64Add),
                            "-=" => self.asm.i(I::F64Sub),
                            "*=" => self.asm.i(I::F64Mul),
                            "/=" => self.asm.i(I::F64Div),
                            "%=" => self.asm.i(I::Call(HELPER_MOD)),
                            _ => return None,
                        }
                        self.asm.extend([
                            I::LocalSet(value),
                            I::LocalGet(addr),
                            I::LocalGet(value),
                            I::F64Store(memarg64(0)),
                        ]);
                        Some(())
                    }
                    _ => None,
                }
            }
            "update_expression" => {
                let arg = node
                    .child_by_field_name("argument")
                    .or_else(|| node.named_child(0))?;
                if arg.kind() != "identifier" {
                    return None;
                }
                let name = js_ident(self.text(arg))?;
                let Some(Slot::Scalar(local)) = self.slot(&name) else {
                    return None;
                };
                let op_text = self.text(node);
                self.asm.i(I::LocalGet(local));
                self.asm.i(I::F64Const(1.0.into()));
                if op_text.contains("++") {
                    self.asm.i(I::F64Add);
                } else if op_text.contains("--") {
                    self.asm.i(I::F64Sub);
                } else {
                    return None;
                }
                self.asm.i(I::LocalSet(local));
                Some(())
            }
            _ => None,
        }
    }

    /// `a[idx]` for a declared fixed-size array: leaves the checked
    /// byte address (i32) on the stack via the bounds-guarded helper.
    fn emit_subscript_addr(&mut self, node: tree_sitter::Node) -> Option<()> {
        let object = node.child_by_field_name("object")?;
        if object.kind() != "identifier" {
            return None;
        }
        let name = js_ident(self.text(object))?;
        let Some(Slot::Array { base, len }) = self.slot(&name) else {
            return None;
        };
        self.asm.i(I::I32Const(base as i32));
        self.asm.i(I::I32Const(len as i32));
        self.expr(node.child_by_field_name("index")?)?;
        self.asm.i(I::Call(HELPER_ARR_ADDR));
        Some(())
    }

    /// Emit an expression, leaving exactly one f64 on the stack.
    fn expr(&mut self, node: tree_sitter::Node) -> Option<()> {
        match node.kind() {
            "number" => {
                let value = parse_js_number(self.text(node))?;
                self.asm.i(I::F64Const(value.into()));
                Some(())
            }
            "identifier" => {
                let name = self.text(node);
                match name {
                    "Infinity" => {
                        self.asm.i(I::F64Const(f64::INFINITY.into()));
                        Some(())
                    }
                    "NaN" => {
                        self.asm.i(I::F64Const(f64::NAN.into()));
                        Some(())
                    }
                    _ => {
                        let ident = js_ident(name)?;
                        // Arrays are second-class: array name in scalar
                        // position refuses the compile.
                        match self.slot(&ident) {
                            Some(Slot::Scalar(local)) => {
                                self.asm.i(I::LocalGet(local));
                                Some(())
                            }
                            _ => None,
                        }
                    }
                }
            }
            "subscript_expression" => {
                self.emit_subscript_addr(node)?;
                self.asm.i(I::F64Load(memarg64(0)));
                Some(())
            }
            "member_expression" => {
                // Only `<array>.length`, folded to its constant.
                let object = node.child_by_field_name("object")?;
                let property = node.child_by_field_name("property")?;
                if object.kind() != "identifier" || self.text(property) != "length" {
                    return None;
                }
                let name = js_ident(self.text(object))?;
                match self.slot(&name) {
                    Some(Slot::Array { len, .. }) => {
                        self.asm.i(I::F64Const((len as f64).into()));
                        Some(())
                    }
                    _ => None,
                }
            }
            "true" => {
                self.asm.i(I::F64Const(1.0.into()));
                Some(())
            }
            "false" => {
                self.asm.i(I::F64Const(0.0.into()));
                Some(())
            }
            "parenthesized_expression" => self.expr(node.named_child(0)?),
            "unary_expression" => {
                let op = node.child_by_field_name("operator").map(|n| self.text(n))?;
                match op {
                    "-" => {
                        self.expr(node.child_by_field_name("argument")?)?;
                        self.asm.i(I::F64Neg);
                        Some(())
                    }
                    "+" => self.expr(node.child_by_field_name("argument")?),
                    "!" => {
                        self.expr(node.child_by_field_name("argument")?)?;
                        self.emit_truthy();
                        self.asm.extend([I::I32Eqz, I::F64ConvertI32U]);
                        Some(())
                    }
                    _ => None,
                }
            }
            "binary_expression" => {
                let left = node.child_by_field_name("left")?;
                let right = node.child_by_field_name("right")?;
                let op = node.child_by_field_name("operator").map(|n| self.text(n))?;
                match op {
                    "+" | "-" | "*" | "/" => {
                        self.expr(left)?;
                        self.expr(right)?;
                        self.asm.i(match op {
                            "+" => I::F64Add,
                            "-" => I::F64Sub,
                            "*" => I::F64Mul,
                            _ => I::F64Div,
                        });
                        Some(())
                    }
                    "%" => {
                        self.expr(left)?;
                        self.expr(right)?;
                        self.asm.i(I::Call(HELPER_MOD));
                        Some(())
                    }
                    // Bitwise family: EXACT walker semantics —
                    // trunc_sat is Rust's saturating cast (NaN → 0),
                    // convert is Rust's `as f64`. Full-domain answers.
                    "&" | "|" | "^" => {
                        self.expr(left)?;
                        self.asm.i(I::I64TruncSatF64S);
                        self.expr(right)?;
                        self.asm.i(I::I64TruncSatF64S);
                        self.asm.i(match op {
                            "&" => I::I64And,
                            "|" => I::I64Or,
                            _ => I::I64Xor,
                        });
                        self.asm.i(I::F64ConvertI64S);
                        Some(())
                    }
                    "<<" | ">>" => {
                        self.expr(left)?;
                        self.asm.i(I::I64TruncSatF64S);
                        self.expr(right)?;
                        self.asm.extend([
                            I::I64TruncSatF64S,
                            I::I64Const(0x1f),
                            I::I64And,
                            if op == "<<" { I::I64Shl } else { I::I64ShrS },
                            I::F64ConvertI64S,
                        ]);
                        Some(())
                    }
                    ">>>" => {
                        // (l as u32) >> ((r as u32) & 0x1f) — wasm's
                        // i32.shr_u masks the count mod 32 itself.
                        self.expr(left)?;
                        self.asm.i(I::I32TruncSatF64U);
                        self.expr(right)?;
                        self.asm
                            .extend([I::I32TruncSatF64U, I::I32ShrU, I::F64ConvertI32U]);
                        Some(())
                    }
                    "<" | "<=" | ">" | ">=" | "==" | "===" | "!=" | "!==" => {
                        self.expr(left)?;
                        self.expr(right)?;
                        self.asm.i(match op {
                            "<" => I::F64Lt,
                            "<=" => I::F64Le,
                            ">" => I::F64Gt,
                            ">=" => I::F64Ge,
                            "==" | "===" => I::F64Eq,
                            _ => I::F64Ne,
                        });
                        self.asm.i(I::F64ConvertI32U);
                        Some(())
                    }
                    "&&" | "||" => {
                        let tmp = self.asm.local(ValType::F64);
                        self.expr(left)?;
                        self.asm.i(I::LocalSet(tmp));
                        self.asm.i(I::LocalGet(tmp));
                        self.emit_truthy();
                        self.asm.i(I::If(BlockType::Result(ValType::F64)));
                        if op == "&&" {
                            self.expr(right)?;
                            self.asm.i(I::Else);
                            self.asm.i(I::LocalGet(tmp));
                        } else {
                            self.asm.i(I::LocalGet(tmp));
                            self.asm.i(I::Else);
                            self.expr(right)?;
                        }
                        self.asm.i(I::End);
                        Some(())
                    }
                    _ => None,
                }
            }
            "call_expression" => {
                let callee = node.child_by_field_name("function")?;
                let args_node = node.child_by_field_name("arguments")?;
                let mut args: Vec<tree_sitter::Node> = Vec::new();
                let mut walker = args_node.walk();
                for arg in args_node.named_children(&mut walker) {
                    if arg.kind() == "comment" {
                        continue;
                    }
                    args.push(arg);
                }
                match callee.kind() {
                    "identifier" => {
                        let name = js_ident(self.text(callee))?;
                        let arity = self.funcs.get(&name)?.params.len();
                        if arity != args.len() {
                            // JS undefined-fill / extra-arg semantics:
                            // outside the class.
                            return None;
                        }
                        self.compile_function(&name)?;
                        let index = *self.indices.get(&name)?;
                        for arg in args {
                            self.expr(arg)?;
                        }
                        self.asm.i(I::Call(index));
                        Some(())
                    }
                    "member_expression" => {
                        let object = callee.child_by_field_name("object")?;
                        let property = callee.child_by_field_name("property")?;
                        if object.kind() != "identifier" || self.text(object) != "Math" {
                            return None;
                        }
                        self.math_intrinsic(self.text(property), &args)
                    }
                    _ => None,
                }
            }
            _ => None,
        }
    }

    /// The exactly-representable Math.* subset (see aot_c). floor/ceil/
    /// trunc/abs/sqrt are native single instructions, IEEE-identical to
    /// the walker; round/min/max go through the semantics helpers.
    fn math_intrinsic(&mut self, name: &str, args: &[tree_sitter::Node]) -> Option<()> {
        match (name, args.len()) {
            ("floor", 1) | ("ceil", 1) | ("trunc", 1) | ("abs", 1) | ("sqrt", 1) => {
                self.expr(args[0])?;
                self.asm.i(match name {
                    "floor" => I::F64Floor,
                    "ceil" => I::F64Ceil,
                    "trunc" => I::F64Trunc,
                    "abs" => I::F64Abs,
                    _ => I::F64Sqrt,
                });
                Some(())
            }
            ("round", 1) => {
                self.expr(args[0])?;
                self.asm.i(I::Call(HELPER_ROUND));
                Some(())
            }
            ("min", 0) => {
                self.asm.i(I::F64Const(f64::INFINITY.into()));
                Some(())
            }
            ("max", 0) => {
                self.asm.i(I::F64Const(f64::NEG_INFINITY.into()));
                Some(())
            }
            ("min", _) | ("max", _) => {
                let helper = if name == "min" {
                    HELPER_MIN
                } else {
                    HELPER_MAX
                };
                self.expr(args[0])?;
                for arg in &args[1..] {
                    self.expr(*arg)?;
                    self.asm.i(I::Call(helper));
                }
                Some(())
            }
            _ => None,
        }
    }
}

// ── Certified scalar-string class (json-v1) ─────────────────────────
//
// The string-capable sibling of the numeric-loop class: a single
// exported TS/JS function over ONE object parameter, compiled to a
// json-v1 module over the SAME bump-allocator ABI as the fixture
// emitters. String values at runtime are (ptr, len) pairs in linear
// memory; string locals are pairs of i32 wasm locals.
//
// Accepted grammar (everything else refuses the compile — fail closed):
// - entry: one identifier parameter; the parameter may ONLY appear as
//   `input.field` member reads (bare use, nested members, computed
//   subscripts all refuse);
// - statements: `let`/`const`/`var` declarations, plain `=` assignment,
//   numeric `+= -= *= /= %=` and `++`/`--`, `return`, `if`/`else`,
//   nested blocks. NO loops of any kind in this class;
// - string expressions: string literals (no escape sequences, no bytes
//   that would need JSON output escaping), template literals, `+`
//   concatenation where at least one side is statically a string;
// - numeric expressions: the numeric-loop subset minus arrays/bitwise/
//   user helper calls — literals, numeric locals and fields, `+ - * /
//   %`, comparisons, `&& || !`, unary `-`/`+`, and the exactly-
//   representable Math.* subset (floor/ceil/trunc/abs/sqrt/round/
//   min/max);
// - conditions: string equality (`== === != !==`, byte compare) or
//   numeric truthiness;
// - NO string `.length`/indexing/methods, NO user function calls.
//
// Field typing (inferred, fail-closed on conflicts):
// - fields used in hard numeric contexts parse strict JSON integers
//   (optional '-', no leading zeros, magnitude < 2^32; '.', 'e', 'E'
//   trap — float parsing stays walker jurisdiction);
// - fields compared with `==`/`===`/`!=`/`!==` (directly or through a
//   plain alias local) are STRICT string reads: a JSON number there
//   traps, because byte-comparing formatted digits would diverge from
//   JS `===` (42 === "42" is false);
// - fields used only in template/concat position are POLYMORPHIC at
//   runtime: a JSON string is used verbatim, a JSON integer is
//   formatted to digits — exactly JS template stringification;
// - `return` of a raw polymorphic field forces the strict read (a bare
//   numeric field return would otherwise emit a *quoted* number).
//
// Number→string conversion answers ONLY for integral f64 with
// |v| ≤ 2^53 (the fibonacci digit-formatting convention plus a '-'
// sign); non-integral formatting traps. Output bytes are JSON-safe BY
// CONSTRUCTION: literals are compile-checked, input strings trap on
// escapes/control bytes at read time (`emit_read_string_value`), and
// digits never need escaping. `input.a + input.b` with both sides
// statically unknown is ambiguous (JS could add or concatenate) and
// refuses; `input.a + 1` likewise. All field reads are hoisted to the
// module prologue (a missing field declines even when the walker's
// control flow would not read it — decline-only, never divergent).

const STR_FN_MOD: u32 = 4;
const STR_FN_ROUND: u32 = 5;
const STR_FN_MIN: u32 = 6;
const STR_FN_MAX: u32 = 7;
const STR_FN_FMT: u32 = 8;
const STR_FN_STREQ: u32 = 9;
/// Literal data for the string class sits above the digit scratch
/// region ([SCRATCH_BASE, SCRATCH_BASE + 32)).
const STR_DATA_BASE: u32 = 160;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum FieldMode {
    Num,
    Strict,
    Poly,
}

/// Static type lattice: `Unknown` is a polymorphic (runtime-typed)
/// string-representable value — a poly field or a plain alias of one.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum STy {
    Num,
    Str,
    Unknown,
}

#[derive(Debug, Default, Clone)]
struct FieldDemand {
    num: bool,
    strict: bool,
}

struct StringModule {
    bytes: Vec<u8>,
    pages: u64,
}

/// Direct entry to the certified scalar-string class: core module bytes
/// (no manifest section), or None when the program is outside the
/// class. The surface the parity harness drives.
pub fn string_class_wasm_bytes(source: &str, export_name: &str) -> Option<Vec<u8>> {
    string_class_wasm(source, export_name).map(|module| module.bytes)
}

fn string_class_wasm(source: &str, export_name: &str) -> Option<StringModule> {
    let mut parser = tree_sitter::Parser::new();
    parser
        .set_language(&tree_sitter_typescript::LANGUAGE_TYPESCRIPT.into())
        .ok()?;
    let tree = parser.parse(source, None)?;

    let mut entry: Option<(String, tree_sitter::Node)> = None;
    let mut stack = vec![tree.root_node()];
    while let Some(node) = stack.pop() {
        if node.kind() == "function_declaration" {
            let name_node = node.child_by_field_name("name")?;
            if wasm_node_text(name_node, source) == export_name {
                let params_node = node.child_by_field_name("parameters")?;
                let mut params: Vec<String> = Vec::new();
                let mut walker = params_node.walk();
                for param in params_node.named_children(&mut walker) {
                    let pattern = match param.kind() {
                        "required_parameter" => param.child_by_field_name("pattern")?,
                        "identifier" => param,
                        "comment" => continue,
                        _ => return None,
                    };
                    if pattern.kind() != "identifier" {
                        return None;
                    }
                    params.push(js_ident(wasm_node_text(pattern, source))?);
                }
                if params.len() != 1 {
                    return None;
                }
                entry = Some((params.remove(0), node.child_by_field_name("body")?));
                break;
            }
        }
        let mut walker = node.walk();
        for child in node.named_children(&mut walker) {
            stack.push(child);
        }
    }
    let (param, body) = entry?;

    let inference = StringClassInference::run(source, &param, body)?;
    StringClassEmitter::emit(source, &param, body, &inference)
}

/// `input.field`: object is exactly the entry parameter, joined by a
/// plain "." (optional chaining refuses), property a valid identifier.
fn field_of_member(node: tree_sitter::Node, source: &str, param: &str) -> Option<String> {
    if node.kind() != "member_expression" {
        return None;
    }
    let object = node.child_by_field_name("object")?;
    let property = node.child_by_field_name("property")?;
    if object.kind() != "identifier" || wasm_node_text(object, source) != param {
        return None;
    }
    if property.kind() != "property_identifier" {
        return None;
    }
    if source.get(object.end_byte()..property.start_byte()) != Some(".") {
        return None;
    }
    js_ident(wasm_node_text(property, source))
}

fn collect_fields(
    node: tree_sitter::Node,
    source: &str,
    param: &str,
    order: &mut Vec<String>,
    seen: &mut HashSet<String>,
) {
    if let Some(field) = field_of_member(node, source, param) {
        if seen.insert(field.clone()) {
            order.push(field);
        }
    }
    let mut walker = node.walk();
    for child in node.named_children(&mut walker) {
        collect_fields(child, source, param, order, seen);
    }
}

struct StringClassInference {
    modes: HashMap<String, FieldMode>,
    /// Field names in first-occurrence (source pre-order) order — the
    /// deterministic prologue read order.
    order: Vec<String>,
}

impl StringClassInference {
    fn run(
        source: &str,
        param: &str,
        body: tree_sitter::Node,
    ) -> Option<StringClassInference> {
        let mut order = Vec::new();
        let mut seen = HashSet::new();
        collect_fields(body, source, param, &mut order, &mut seen);

        let mut pass = InferPass {
            source,
            param,
            aliases: HashMap::new(),
            demands: HashMap::new(),
            scopes: Vec::new(),
            changed: true,
        };
        let mut rounds = 0;
        while pass.changed && rounds < 12 {
            pass.changed = false;
            pass.scopes.clear();
            pass.block(body);
            rounds += 1;
        }

        let mut modes = HashMap::new();
        for field in &order {
            let demand = pass.demands.get(field).cloned().unwrap_or_default();
            if demand.num && demand.strict {
                // The same field cannot be both a strict string and a
                // number — outside the class.
                return None;
            }
            let mode = if demand.num {
                FieldMode::Num
            } else if demand.strict {
                FieldMode::Strict
            } else {
                FieldMode::Poly
            };
            modes.insert(field.clone(), mode);
        }
        Some(StringClassInference { modes, order })
    }
}

/// One monotone inference pass: field demands only ever escalate
/// (Poly → Num / Strict), so iterating to fixpoint terminates and the
/// result is order-independent.
struct InferPass<'s> {
    source: &'s str,
    param: &'s str,
    /// local name → fields it may plainly alias (flow-insensitive).
    aliases: HashMap<String, HashSet<String>>,
    demands: HashMap<String, FieldDemand>,
    scopes: Vec<HashMap<String, STy>>,
    changed: bool,
}

impl<'s> InferPass<'s> {
    fn text(&self, node: tree_sitter::Node) -> &'s str {
        wasm_node_text(node, self.source)
    }

    fn demand(&mut self, field: &str, strict: bool) {
        let demand = self.demands.entry(field.to_string()).or_default();
        let slot = if strict {
            &mut demand.strict
        } else {
            &mut demand.num
        };
        if !*slot {
            *slot = true;
            self.changed = true;
        }
    }

    /// Fields a value RAWLY carries (bare member read, plain alias
    /// local, parens). Concats/templates stringify in JS itself, so
    /// they are not raw.
    fn raw_fields(&self, node: tree_sitter::Node) -> HashSet<String> {
        let node = strip_parens_ts(node);
        if let Some(field) = field_of_member(node, self.source, self.param) {
            return HashSet::from([field]);
        }
        if node.kind() == "identifier" {
            if let Some(set) = self.aliases.get(self.text(node)) {
                return set.clone();
            }
        }
        HashSet::new()
    }

    fn demand_all(&mut self, node: tree_sitter::Node, strict: bool) {
        for field in self.raw_fields(node) {
            self.demand(&field, strict);
        }
    }

    fn mode(&self, field: &str) -> FieldMode {
        match self.demands.get(field) {
            Some(demand) if demand.num => FieldMode::Num,
            Some(demand) if demand.strict => FieldMode::Strict,
            _ => FieldMode::Poly,
        }
    }

    fn ty_of(&self, node: tree_sitter::Node) -> STy {
        let node = strip_parens_ts(node);
        match node.kind() {
            "string" | "template_string" => STy::Str,
            "number" | "true" | "false" => STy::Num,
            "unary_expression" | "call_expression" | "update_expression" => STy::Num,
            "identifier" => match self.text(node) {
                "Infinity" | "NaN" => STy::Num,
                name => self
                    .scopes
                    .iter()
                    .rev()
                    .find_map(|scope| scope.get(name).copied())
                    .unwrap_or(STy::Unknown),
            },
            "member_expression" => match field_of_member(node, self.source, self.param) {
                Some(field) => match self.mode(&field) {
                    FieldMode::Num => STy::Num,
                    FieldMode::Strict => STy::Str,
                    FieldMode::Poly => STy::Unknown,
                },
                None => STy::Unknown,
            },
            "binary_expression" => {
                let op = node
                    .child_by_field_name("operator")
                    .map(|n| self.text(n))
                    .unwrap_or("");
                if op == "+" {
                    let left = node
                        .child_by_field_name("left")
                        .map(|n| self.ty_of(n))
                        .unwrap_or(STy::Unknown);
                    let right = node
                        .child_by_field_name("right")
                        .map(|n| self.ty_of(n))
                        .unwrap_or(STy::Unknown);
                    if left == STy::Str || right == STy::Str {
                        STy::Str
                    } else if left == STy::Num && right == STy::Num {
                        STy::Num
                    } else {
                        STy::Unknown
                    }
                } else {
                    STy::Num
                }
            }
            _ => STy::Unknown,
        }
    }

    fn block(&mut self, block: tree_sitter::Node) {
        self.scopes.push(HashMap::new());
        let mut walker = block.walk();
        for stmt in block.named_children(&mut walker) {
            self.stmt(stmt);
        }
        self.scopes.pop();
    }

    fn nested(&mut self, stmt: tree_sitter::Node) {
        if stmt.kind() == "statement_block" {
            self.block(stmt)
        } else {
            self.stmt(stmt)
        }
    }

    fn stmt(&mut self, stmt: tree_sitter::Node) {
        match stmt.kind() {
            "lexical_declaration" | "variable_declaration" => {
                let mut walker = stmt.walk();
                for declarator in stmt.named_children(&mut walker) {
                    if declarator.kind() != "variable_declarator" {
                        continue;
                    }
                    let Some(name_node) = declarator.child_by_field_name("name") else {
                        continue;
                    };
                    let Some(value) = declarator.child_by_field_name("value") else {
                        continue;
                    };
                    self.expr(value);
                    let ty = self.ty_of(value);
                    let name = self.text(name_node).to_string();
                    let raw = self.raw_fields(value);
                    let entry = self.aliases.entry(name.clone()).or_default();
                    let mut grew = false;
                    for field in raw {
                        grew |= entry.insert(field);
                    }
                    if grew {
                        self.changed = true;
                    }
                    if let Some(scope) = self.scopes.last_mut() {
                        scope.insert(name, ty);
                    }
                }
            }
            "expression_statement" => {
                if let Some(inner) = stmt.named_child(0) {
                    self.assign_like(inner);
                }
            }
            "return_statement" => {
                if let Some(value) = stmt.named_child(0) {
                    self.expr(value);
                    if self.ty_of(value) == STy::Unknown {
                        // A raw poly return would quote a bare number;
                        // force the strict string read instead.
                        self.demand_all(value, true);
                    }
                }
            }
            "if_statement" => {
                if let Some(cond) = stmt.child_by_field_name("condition") {
                    self.cond(cond);
                }
                if let Some(consequence) = stmt.child_by_field_name("consequence") {
                    self.nested(consequence);
                }
                if let Some(alternative) = stmt.child_by_field_name("alternative") {
                    if let Some(else_stmt) = alternative.named_child(0) {
                        self.nested(else_stmt);
                    }
                }
            }
            "statement_block" => self.block(stmt),
            _ => {}
        }
    }

    fn assign_like(&mut self, node: tree_sitter::Node) {
        match node.kind() {
            "assignment_expression" => {
                let left = node.child_by_field_name("left");
                if let Some(right) = node.child_by_field_name("right") {
                    self.expr(right);
                    if let Some(left) = left {
                        if left.kind() == "identifier" {
                            let name = self.text(left).to_string();
                            let raw = self.raw_fields(right);
                            let entry = self.aliases.entry(name).or_default();
                            let mut grew = false;
                            for field in raw {
                                grew |= entry.insert(field);
                            }
                            if grew {
                                self.changed = true;
                            }
                        }
                    }
                }
            }
            "augmented_assignment_expression" => {
                if let Some(left) = node.child_by_field_name("left") {
                    self.demand_all(left, false);
                }
                if let Some(right) = node.child_by_field_name("right") {
                    self.expr(right);
                    self.demand_all(right, false);
                }
            }
            "update_expression" => {
                if let Some(argument) = node.child_by_field_name("argument") {
                    self.demand_all(argument, false);
                }
            }
            _ => self.expr(node),
        }
    }

    fn cond(&mut self, cond: tree_sitter::Node) {
        let cond = strip_parens_ts(cond);
        if cond.kind() == "binary_expression" {
            let op = cond
                .child_by_field_name("operator")
                .map(|n| self.text(n))
                .unwrap_or("");
            if matches!(op, "==" | "===" | "!=" | "!==") {
                self.eq_constraint(cond);
                return;
            }
        }
        self.expr(cond);
        // Bare condition is numeric truthiness (a string field here
        // becomes a numeric read; string inputs then decline).
        self.demand_all(cond, false);
    }

    fn eq_constraint(&mut self, node: tree_sitter::Node) {
        let (Some(left), Some(right)) = (
            node.child_by_field_name("left"),
            node.child_by_field_name("right"),
        ) else {
            return;
        };
        self.expr(left);
        self.expr(right);
        let (tl, tr) = (self.ty_of(left), self.ty_of(right));
        if tl == STy::Num && tr == STy::Num {
            self.demand_all(left, false);
            self.demand_all(right, false);
        } else {
            // Equality over anything string-ish must byte-compare REAL
            // strings: raw fields on both sides become strict reads.
            self.demand_all(left, true);
            self.demand_all(right, true);
        }
    }

    fn expr(&mut self, node: tree_sitter::Node) {
        let node = strip_parens_ts(node);
        match node.kind() {
            "binary_expression" => {
                let op = node
                    .child_by_field_name("operator")
                    .map(|n| self.text(n))
                    .unwrap_or("");
                let left = node.child_by_field_name("left");
                let right = node.child_by_field_name("right");
                match op {
                    "==" | "===" | "!=" | "!==" => self.eq_constraint(node),
                    "+" => {
                        if let (Some(left), Some(right)) = (left, right) {
                            self.expr(left);
                            self.expr(right);
                            let (tl, tr) = (self.ty_of(left), self.ty_of(right));
                            if tl == STy::Str || tr == STy::Str {
                                // concat: poly sides stay poly
                            } else if tl == STy::Num && tr == STy::Num {
                                self.demand_all(left, false);
                                self.demand_all(right, false);
                            }
                            // Unknown-ambiguous `+`: no demand; the
                            // emitter refuses the compile.
                        }
                    }
                    "&&" | "||" | "-" | "*" | "/" | "%" | "<" | "<=" | ">" | ">=" => {
                        for side in [left, right].into_iter().flatten() {
                            self.expr(side);
                            self.demand_all(side, false);
                        }
                    }
                    _ => {
                        for side in [left, right].into_iter().flatten() {
                            self.expr(side);
                        }
                    }
                }
            }
            "unary_expression" => {
                if let Some(argument) = node.child_by_field_name("argument") {
                    self.expr(argument);
                    self.demand_all(argument, false);
                }
            }
            "template_string" => {
                let mut walker = node.walk();
                for child in node.named_children(&mut walker) {
                    if child.kind() == "template_substitution" {
                        if let Some(inner) = child.named_child(0) {
                            self.expr(inner);
                        }
                    }
                }
            }
            "call_expression" => {
                let is_math = node
                    .child_by_field_name("function")
                    .filter(|f| f.kind() == "member_expression")
                    .and_then(|f| f.child_by_field_name("object"))
                    .map(|object| {
                        object.kind() == "identifier" && self.text(object) == "Math"
                    })
                    .unwrap_or(false);
                if let Some(args) = node.child_by_field_name("arguments") {
                    let mut walker = args.walk();
                    for arg in args.named_children(&mut walker) {
                        if arg.kind() == "comment" {
                            continue;
                        }
                        self.expr(arg);
                        if is_math {
                            self.demand_all(arg, false);
                        }
                    }
                }
            }
            _ => {}
        }
    }
}

// ── scalar-string emitter ───────────────────────────────────────────

#[derive(Debug, Clone, Copy)]
enum StrSlot {
    Num(u32),
    Pair { ptr: u32, len: u32, ty: STy },
}

#[derive(Debug, Clone, Copy)]
struct FieldSlots {
    mode: FieldMode,
    num: u32,
    ptr: u32,
    len: u32,
}

/// A flattened concatenation part, resolved left-to-right.
enum StrPart<'t> {
    Lit { off: u32, len: u32 },
    Pair { ptr: u32, len: u32 },
    Num(tree_sitter::Node<'t>),
}

enum ResolvedPart {
    Lit { off: u32, len: u32 },
    Pair { ptr: u32, len: u32 },
}

struct StringClassEmitter<'s, 'i> {
    source: &'s str,
    param: &'s str,
    inference: &'i StringClassInference,
    field_slots: HashMap<String, FieldSlots>,
    scopes: Vec<HashMap<String, StrSlot>>,
    asm: Asm,
    /// Literal blob placed at STR_DATA_BASE.
    data: Vec<u8>,
    limit: u32,
    cursor: u32,
    ch: u32,
}

impl<'s, 'i> StringClassEmitter<'s, 'i> {
    fn emit(
        source: &'s str,
        param: &'s str,
        body: tree_sitter::Node,
        inference: &'i StringClassInference,
    ) -> Option<StringModule> {
        let mut asm = Asm::new(2); // params: ptr, len
        let limit = asm.local(ValType::I32);
        let cursor = asm.local(ValType::I32);
        let ch = asm.local(ValType::I32);
        asm.extend([
            I::LocalGet(0),
            I::LocalGet(1),
            I::I32Add,
            I::LocalSet(limit),
        ]);

        let mut emitter = StringClassEmitter {
            source,
            param,
            inference,
            field_slots: HashMap::new(),
            scopes: Vec::new(),
            asm,
            data: Vec::new(),
            limit,
            cursor,
            ch,
        };
        emitter.emit_field_prologue()?;
        emitter.statement_block(body)?;
        // Falling off the end is JS `undefined` — decline.
        emitter.asm.i(I::Unreachable);

        let data_len = emitter.data.len() as u32;
        let heap_base = ((STR_DATA_BASE + data_len + 7) & !7).max(HEAP_BASE as u32);
        let pages = (heap_base as u64).div_ceil(WASM_PAGE).max(2);
        let main = FuncSpec {
            params: vec![ValType::I32, ValType::I32],
            results: vec![ValType::I32],
            locals: emitter.asm.locals,
            ins: emitter.asm.ins,
        };
        let data = if emitter.data.is_empty() {
            vec![]
        } else {
            vec![(STR_DATA_BASE, emitter.data)]
        };
        let bytes = assemble(&ModuleSpec {
            pages_min: pages,
            globals: vec![GlobalInit::I32(heap_base as i32), GlobalInit::I32(0)],
            data,
            funcs: vec![
                json_alloc_func(),
                main,
                json_result_len_func(),
                json_free_func(),
                helper_js_mod(),
                helper_js_round(),
                helper_js_min_max(true),
                helper_js_min_max(false),
                helper_fmt_int(),
                helper_str_eq(),
            ],
            func_exports: vec![
                ("gnosis_alloc", 0),
                ("main", 1),
                ("gnosis_result_len", 2),
                ("gnosis_free", 3),
            ],
        });
        Some(StringModule { bytes, pages })
    }

    fn text(&self, node: tree_sitter::Node) -> &'s str {
        wasm_node_text(node, self.source)
    }

    fn op_text(&self, node: tree_sitter::Node) -> Option<&'s str> {
        node.child_by_field_name("operator").map(|n| self.text(n))
    }

    fn slot(&self, name: &str) -> Option<StrSlot> {
        self.scopes
            .iter()
            .rev()
            .find_map(|scope| scope.get(name).copied())
    }

    /// All field reads hoist to the module prologue in first-occurrence
    /// order. Hoisting can only ADD declines (missing/ill-typed fields
    /// trap even when the walker's control flow would skip them) —
    /// never a divergent answer.
    fn emit_field_prologue(&mut self) -> Option<()> {
        let (limit, cursor, ch) = (self.limit, self.cursor, self.ch);
        for name in &self.inference.order {
            let mode = *self.inference.modes.get(name)?;
            let needle = format!("\"{name}\"");
            emit_find_needle(&mut self.asm, needle.as_bytes(), 0, limit, cursor);
            emit_skip_colon_ws(&mut self.asm, limit, cursor, ch);
            let slots = match mode {
                FieldMode::Num => {
                    let value = self.asm.local(ValType::F64);
                    self.emit_parse_json_number(value);
                    FieldSlots {
                        mode,
                        num: value,
                        ptr: 0,
                        len: 0,
                    }
                }
                FieldMode::Strict => {
                    let vstart = self.asm.local(ValType::I32);
                    let vlen = self.asm.local(ValType::I32);
                    emit_read_string_value(&mut self.asm, limit, cursor, ch, vstart, vlen);
                    FieldSlots {
                        mode,
                        num: 0,
                        ptr: vstart,
                        len: vlen,
                    }
                }
                FieldMode::Poly => {
                    let vstart = self.asm.local(ValType::I32);
                    let vlen = self.asm.local(ValType::I32);
                    let tmp = self.asm.local(ValType::F64);
                    // skip_colon_ws leaves cursor on an in-bounds,
                    // non-whitespace byte — peek it.
                    self.asm.extend([
                        I::LocalGet(cursor),
                        I::I32Load8U(memarg8(0)),
                        I::I32Const(b'"' as i32),
                        I::I32Eq,
                        I::If(BlockType::Empty),
                    ]);
                    emit_read_string_value(&mut self.asm, limit, cursor, ch, vstart, vlen);
                    self.asm.i(I::Else);
                    self.emit_parse_json_number(tmp);
                    self.asm.extend([
                        I::LocalGet(tmp),
                        I::Call(STR_FN_FMT),
                        I::LocalSet(vlen),
                        I::LocalSet(vstart),
                        I::End,
                    ]);
                    FieldSlots {
                        mode,
                        num: 0,
                        ptr: vstart,
                        len: vlen,
                    }
                }
            };
            self.field_slots.insert(name.clone(), slots);
        }
        Some(())
    }

    /// Strict JSON integer at `cursor`: optional '-', no leading zeros,
    /// digit accumulation exact-fenced below 2^32 (the fibonacci
    /// convention), trailing '.', 'e', 'E' decline. Leaves the value in
    /// f64 local `value`.
    fn emit_parse_json_number(&mut self, value: u32) {
        let (limit, cursor, ch) = (self.limit, self.cursor, self.ch);
        let neg = self.asm.local(ValType::I32);
        let a = &mut self.asm;
        emit_bounds_or_trap(a, cursor, limit);
        a.extend([
            I::I32Const(0),
            I::LocalSet(neg),
            I::F64Const(0.0.into()),
            I::LocalSet(value),
            I::LocalGet(cursor),
            I::I32Load8U(memarg8(0)),
            I::I32Const(b'-' as i32),
            I::I32Eq,
            I::If(BlockType::Empty),
            I::I32Const(1),
            I::LocalSet(neg),
            I::LocalGet(cursor),
            I::I32Const(1),
            I::I32Add,
            I::LocalSet(cursor),
            I::End,
        ]);
        emit_bounds_or_trap(a, cursor, limit);
        // first char must be a digit
        a.extend([
            I::LocalGet(cursor),
            I::I32Load8U(memarg8(0)),
            I::LocalTee(ch),
            I::I32Const(b'0' as i32),
            I::I32LtU,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
            I::LocalGet(ch),
            I::I32Const(b'9' as i32),
            I::I32GtU,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
        ]);
        // '0' must stand alone (leading zeros are invalid JSON — the
        // walker errors there, so answering would diverge).
        a.extend([
            I::LocalGet(ch),
            I::I32Const(b'0' as i32),
            I::I32Eq,
            I::If(BlockType::Empty),
            I::LocalGet(cursor),
            I::I32Const(1),
            I::I32Add,
            I::LocalTee(cursor),
            I::LocalGet(limit),
            I::I32LtS,
            I::If(BlockType::Empty),
            I::LocalGet(cursor),
            I::I32Load8U(memarg8(0)),
            I::LocalTee(ch),
            I::I32Const(b'0' as i32),
            I::I32GeU,
            I::LocalGet(ch),
            I::I32Const(b'9' as i32),
            I::I32LeU,
            I::I32And,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
            I::End,
            I::Else,
        ]);
        // accumulate digits (exact while value < 2^32 by the fence)
        a.i(I::Block(BlockType::Empty));
        a.i(I::Loop(BlockType::Empty));
        a.extend([
            I::LocalGet(cursor),
            I::LocalGet(limit),
            I::I32GeS,
            I::BrIf(1),
            I::LocalGet(cursor),
            I::I32Load8U(memarg8(0)),
            I::LocalTee(ch),
            I::I32Const(b'0' as i32),
            I::I32LtU,
            I::BrIf(1),
            I::LocalGet(ch),
            I::I32Const(b'9' as i32),
            I::I32GtU,
            I::BrIf(1),
            I::LocalGet(value),
            I::F64Const(10.0.into()),
            I::F64Mul,
            I::LocalGet(ch),
            I::I32Const(b'0' as i32),
            I::I32Sub,
            I::F64ConvertI32U,
            I::F64Add,
            I::LocalTee(value),
            I::F64Const(4294967296.0.into()),
            I::F64Ge,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
            I::LocalGet(cursor),
            I::I32Const(1),
            I::I32Add,
            I::LocalSet(cursor),
            I::Br(0),
        ]);
        a.i(I::End);
        a.i(I::End);
        a.i(I::End); // close the '0' If/Else
        // trailing '.', 'e', 'E' means a float literal → decline
        a.extend([
            I::LocalGet(cursor),
            I::LocalGet(limit),
            I::I32LtS,
            I::If(BlockType::Empty),
            I::LocalGet(cursor),
            I::I32Load8U(memarg8(0)),
            I::LocalTee(ch),
            I::I32Const(b'.' as i32),
            I::I32Eq,
            I::LocalGet(ch),
            I::I32Const(b'e' as i32),
            I::I32Eq,
            I::I32Or,
            I::LocalGet(ch),
            I::I32Const(b'E' as i32),
            I::I32Eq,
            I::I32Or,
            I::If(BlockType::Empty),
            I::Unreachable,
            I::End,
            I::End,
        ]);
        a.extend([
            I::LocalGet(neg),
            I::If(BlockType::Empty),
            I::LocalGet(value),
            I::F64Neg,
            I::LocalSet(value),
            I::End,
        ]);
    }

    /// Static type at emission time (uses resolved field modes and
    /// declared slots). None = outside the class.
    fn sty(&self, node: tree_sitter::Node) -> Option<STy> {
        let node = strip_parens_ts(node);
        Some(match node.kind() {
            "string" | "template_string" => STy::Str,
            "number" | "true" | "false" => STy::Num,
            "unary_expression" | "call_expression" => STy::Num,
            "identifier" => match self.text(node) {
                "Infinity" | "NaN" => STy::Num,
                name => match self.slot(name)? {
                    StrSlot::Num(_) => STy::Num,
                    StrSlot::Pair { ty, .. } => ty,
                },
            },
            "member_expression" => {
                let field = field_of_member(node, self.source, self.param)?;
                match self.field_slots.get(&field)?.mode {
                    FieldMode::Num => STy::Num,
                    FieldMode::Strict => STy::Str,
                    FieldMode::Poly => STy::Unknown,
                }
            }
            "binary_expression" => {
                let op = self.op_text(node)?;
                if op == "+" {
                    let left = self.sty(node.child_by_field_name("left")?)?;
                    let right = self.sty(node.child_by_field_name("right")?)?;
                    if left == STy::Str || right == STy::Str {
                        STy::Str
                    } else if left == STy::Num && right == STy::Num {
                        STy::Num
                    } else {
                        // `unknown + unknown` / `unknown + number` is
                        // ambiguous between JS add and concat.
                        return None;
                    }
                } else {
                    STy::Num
                }
            }
            _ => return None,
        })
    }

    fn statement_block(&mut self, block: tree_sitter::Node) -> Option<()> {
        self.scopes.push(HashMap::new());
        let mut walker = block.walk();
        for stmt in block.named_children(&mut walker) {
            self.statement(stmt)?;
        }
        self.scopes.pop();
        Some(())
    }

    fn nested_statement(&mut self, stmt: tree_sitter::Node) -> Option<()> {
        if stmt.kind() == "statement_block" {
            self.statement_block(stmt)
        } else {
            self.statement(stmt)
        }
    }

    fn statement(&mut self, stmt: tree_sitter::Node) -> Option<()> {
        match stmt.kind() {
            "comment" | "empty_statement" => Some(()),
            "lexical_declaration" | "variable_declaration" => {
                let mut walker = stmt.walk();
                for declarator in stmt.named_children(&mut walker) {
                    if declarator.kind() == "comment" {
                        continue;
                    }
                    if declarator.kind() != "variable_declarator" {
                        return None;
                    }
                    self.declarator(declarator)?;
                }
                Some(())
            }
            "expression_statement" => self.assignment_like(stmt.named_child(0)?),
            "return_statement" => self.emit_return(stmt.named_child(0)?),
            "if_statement" => {
                let cond = stmt.child_by_field_name("condition")?;
                self.emit_cond_i32(strip_parens_ts(cond))?;
                self.asm.i(I::If(BlockType::Empty));
                self.nested_statement(stmt.child_by_field_name("consequence")?)?;
                if let Some(alternative) = stmt.child_by_field_name("alternative") {
                    let else_stmt = alternative.named_child(0)?;
                    self.asm.i(I::Else);
                    self.nested_statement(else_stmt)?;
                }
                self.asm.i(I::End);
                Some(())
            }
            "statement_block" => self.statement_block(stmt),
            // Loops (and everything else) are outside the class.
            _ => None,
        }
    }

    fn declared(&self, name: &str) -> bool {
        self.slot(name).is_some()
    }

    fn declarator(&mut self, declarator: tree_sitter::Node) -> Option<()> {
        let name_node = declarator.child_by_field_name("name")?;
        if name_node.kind() != "identifier" {
            return None;
        }
        let name = js_ident(self.text(name_node))?;
        if name == self.param || self.declared(&name) {
            return None;
        }
        let value = declarator.child_by_field_name("value")?;
        let slot = match self.sty(value)? {
            STy::Num => {
                self.num_expr(value)?;
                let local = self.asm.local(ValType::F64);
                self.asm.i(I::LocalSet(local));
                StrSlot::Num(local)
            }
            ty => {
                let (src_ptr, src_len) = self.materialize(value)?;
                // Copy into dedicated locals so reassignment cannot
                // clobber a field's own pair.
                let ptr = self.asm.local(ValType::I32);
                let len = self.asm.local(ValType::I32);
                self.asm.extend([
                    I::LocalGet(src_ptr),
                    I::LocalSet(ptr),
                    I::LocalGet(src_len),
                    I::LocalSet(len),
                ]);
                StrSlot::Pair { ptr, len, ty }
            }
        };
        self.scopes.last_mut()?.insert(name, slot);
        Some(())
    }

    fn assignment_like(&mut self, node: tree_sitter::Node) -> Option<()> {
        match node.kind() {
            "assignment_expression" => {
                let left = node.child_by_field_name("left")?;
                if left.kind() != "identifier" {
                    return None;
                }
                let name = js_ident(self.text(left))?;
                let slot = self.slot(&name)?;
                let right = node.child_by_field_name("right")?;
                match slot {
                    StrSlot::Num(local) => {
                        if self.sty(right)? != STy::Num {
                            return None;
                        }
                        self.num_expr(right)?;
                        self.asm.i(I::LocalSet(local));
                    }
                    StrSlot::Pair { ptr, len, .. } => {
                        if self.sty(right)? == STy::Num {
                            return None;
                        }
                        let (src_ptr, src_len) = self.materialize(right)?;
                        self.asm.extend([
                            I::LocalGet(src_ptr),
                            I::LocalSet(ptr),
                            I::LocalGet(src_len),
                            I::LocalSet(len),
                        ]);
                    }
                }
                Some(())
            }
            "augmented_assignment_expression" => {
                let left = node.child_by_field_name("left")?;
                if left.kind() != "identifier" {
                    return None;
                }
                let name = js_ident(self.text(left))?;
                let Some(StrSlot::Num(local)) = self.slot(&name) else {
                    return None;
                };
                let op = self.op_text(node)?;
                self.asm.i(I::LocalGet(local));
                self.num_expr(node.child_by_field_name("right")?)?;
                match op {
                    "+=" => self.asm.i(I::F64Add),
                    "-=" => self.asm.i(I::F64Sub),
                    "*=" => self.asm.i(I::F64Mul),
                    "/=" => self.asm.i(I::F64Div),
                    "%=" => self.asm.i(I::Call(STR_FN_MOD)),
                    _ => return None,
                }
                self.asm.i(I::LocalSet(local));
                Some(())
            }
            "update_expression" => {
                let argument = node
                    .child_by_field_name("argument")
                    .or_else(|| node.named_child(0))?;
                if argument.kind() != "identifier" {
                    return None;
                }
                let name = js_ident(self.text(argument))?;
                let Some(StrSlot::Num(local)) = self.slot(&name) else {
                    return None;
                };
                let op_text = self.text(node);
                self.asm.i(I::LocalGet(local));
                self.asm.i(I::F64Const(1.0.into()));
                if op_text.contains("++") {
                    self.asm.i(I::F64Add);
                } else if op_text.contains("--") {
                    self.asm.i(I::F64Sub);
                } else {
                    return None;
                }
                self.asm.i(I::LocalSet(local));
                Some(())
            }
            _ => None,
        }
    }

    fn emit_return(&mut self, value: tree_sitter::Node) -> Option<()> {
        match self.sty(value)? {
            STy::Num => {
                self.num_expr(value)?;
                let ptr = self.asm.local(ValType::I32);
                let len = self.asm.local(ValType::I32);
                self.asm.extend([
                    I::Call(STR_FN_FMT),
                    I::LocalSet(len),
                    I::LocalSet(ptr),
                    I::LocalGet(len),
                    I::GlobalSet(JSON_GLOBAL_RESULT_LEN),
                    I::LocalGet(ptr),
                    I::Return,
                ]);
                Some(())
            }
            STy::Str => {
                let (ptr, len) = self.materialize(value)?;
                let total = self.asm.local(ValType::I32);
                let out = self.asm.local(ValType::I32);
                self.asm.extend([
                    I::LocalGet(len),
                    I::I32Const(2),
                    I::I32Add,
                    I::LocalTee(total),
                    I::Call(JSON_FN_ALLOC),
                    I::LocalSet(out),
                    I::LocalGet(out),
                    I::I32Const(b'"' as i32),
                    I::I32Store8(memarg8(0)),
                    I::LocalGet(out),
                    I::I32Const(1),
                    I::I32Add,
                    I::LocalGet(ptr),
                    I::LocalGet(len),
                    I::MemoryCopy {
                        src_mem: 0,
                        dst_mem: 0,
                    },
                    I::LocalGet(out),
                    I::I32Const(1),
                    I::I32Add,
                    I::LocalGet(len),
                    I::I32Add,
                    I::I32Const(b'"' as i32),
                    I::I32Store8(memarg8(0)),
                    I::LocalGet(total),
                    I::GlobalSet(JSON_GLOBAL_RESULT_LEN),
                    I::LocalGet(out),
                    I::Return,
                ]);
                Some(())
            }
            // Raw poly return: inference forces the strict read, so
            // reaching here means an uncovered path — fail closed.
            STy::Unknown => None,
        }
    }

    /// Condition → i32 on the stack.
    fn emit_cond_i32(&mut self, cond: tree_sitter::Node) -> Option<()> {
        let cond = strip_parens_ts(cond);
        if cond.kind() == "binary_expression" {
            let op = self.op_text(cond)?;
            if matches!(op, "==" | "===" | "!=" | "!==") {
                let left = cond.child_by_field_name("left")?;
                let right = cond.child_by_field_name("right")?;
                let (tl, tr) = (self.sty(left)?, self.sty(right)?);
                if tl == STy::Str || tr == STy::Str {
                    self.emit_str_eq(left, right, tl, tr)?;
                    if op.starts_with('!') {
                        self.asm.i(I::I32Eqz);
                    }
                    return Some(());
                }
            }
        }
        self.num_expr(cond)?;
        self.emit_truthy();
        Some(())
    }

    /// Byte-compare two string expressions; leaves i32 0/1.
    fn emit_str_eq(
        &mut self,
        left: tree_sitter::Node,
        right: tree_sitter::Node,
        tl: STy,
        tr: STy,
    ) -> Option<()> {
        // Both sides must be REAL strings; a Num or raw-poly operand
        // against a string would need JS coercion/identity semantics.
        if tl != STy::Str || tr != STy::Str {
            return None;
        }
        let (pa, la) = self.materialize(left)?;
        let (pb, lb) = self.materialize(right)?;
        self.asm.extend([
            I::LocalGet(pa),
            I::LocalGet(la),
            I::LocalGet(pb),
            I::LocalGet(lb),
            I::Call(STR_FN_STREQ),
        ]);
        Some(())
    }

    /// f64 on stack → truthy i32 (NaN and 0 falsy).
    fn emit_truthy(&mut self) {
        let tmp = self.asm.local(ValType::F64);
        self.asm.extend([
            I::LocalTee(tmp),
            I::LocalGet(tmp),
            I::F64Eq,
            I::LocalGet(tmp),
            I::F64Const(0.0.into()),
            I::F64Ne,
            I::I32And,
        ]);
    }

    /// String-literal content bytes; refuses escape sequences and any
    /// byte that would need JSON output escaping.
    fn string_literal_bytes(&self, node: tree_sitter::Node) -> Option<Vec<u8>> {
        let mut bytes = Vec::new();
        let mut walker = node.walk();
        for child in node.named_children(&mut walker) {
            match child.kind() {
                "string_fragment" => bytes.extend_from_slice(self.text(child).as_bytes()),
                // Escape sequences (and anything else) are walker
                // jurisdiction.
                _ => return None,
            }
        }
        Self::json_safe(&bytes)?;
        Some(bytes)
    }

    /// Output bytes must never need JSON escaping: `"`, `\`, and
    /// control bytes refuse the compile.
    fn json_safe(bytes: &[u8]) -> Option<()> {
        if bytes
            .iter()
            .any(|&b| b == b'"' || b == b'\\' || b < 0x20)
        {
            return None;
        }
        Some(())
    }

    fn lit_part<'t>(&mut self, bytes: &[u8]) -> StrPart<'t> {
        let off = STR_DATA_BASE + self.data.len() as u32;
        self.data.extend_from_slice(bytes);
        StrPart::Lit {
            off,
            len: bytes.len() as u32,
        }
    }

    fn push_chunk<'t>(&mut self, chunk: &str, parts: &mut Vec<StrPart<'t>>) -> Option<()> {
        if chunk.is_empty() {
            return Some(());
        }
        Self::json_safe(chunk.as_bytes())?;
        let part = self.lit_part(chunk.as_bytes());
        parts.push(part);
        Some(())
    }

    /// Route one concat operand: numeric expressions format to digits,
    /// string-ish expressions flatten recursively.
    fn flatten_part<'t>(
        &mut self,
        node: tree_sitter::Node<'t>,
        parts: &mut Vec<StrPart<'t>>,
    ) -> Option<()> {
        match self.sty(node)? {
            STy::Num => {
                parts.push(StrPart::Num(node));
                Some(())
            }
            _ => self.flatten(node, parts),
        }
    }

    fn flatten<'t>(
        &mut self,
        node: tree_sitter::Node<'t>,
        parts: &mut Vec<StrPart<'t>>,
    ) -> Option<()> {
        let node = strip_parens_ts(node);
        match node.kind() {
            "string" => {
                let bytes = self.string_literal_bytes(node)?;
                let part = self.lit_part(&bytes);
                parts.push(part);
                Some(())
            }
            "template_string" => {
                // Literal chunks recovered by byte range (grammar-
                // version-proof); escape sequences appear as raw
                // backslashes and refuse via json_safe.
                let content_start = node.start_byte() + 1;
                let content_end = node.end_byte().checked_sub(1)?;
                let mut pos = content_start;
                let mut walker = node.walk();
                let subs: Vec<tree_sitter::Node> = node
                    .named_children(&mut walker)
                    .filter(|child| child.kind() == "template_substitution")
                    .collect();
                for sub in subs {
                    let chunk = self.source.get(pos..sub.start_byte())?.to_string();
                    self.push_chunk(&chunk, parts)?;
                    self.flatten_part(sub.named_child(0)?, parts)?;
                    pos = sub.end_byte();
                }
                let tail = self.source.get(pos..content_end)?.to_string();
                self.push_chunk(&tail, parts)
            }
            "identifier" => match self.slot(self.text(node))? {
                StrSlot::Pair { ptr, len, .. } => {
                    parts.push(StrPart::Pair { ptr, len });
                    Some(())
                }
                StrSlot::Num(_) => {
                    parts.push(StrPart::Num(node));
                    Some(())
                }
            },
            "member_expression" => {
                let field = field_of_member(node, self.source, self.param)?;
                let slots = *self.field_slots.get(&field)?;
                match slots.mode {
                    FieldMode::Num => parts.push(StrPart::Num(node)),
                    _ => parts.push(StrPart::Pair {
                        ptr: slots.ptr,
                        len: slots.len,
                    }),
                }
                Some(())
            }
            "binary_expression" => {
                if self.op_text(node)? != "+" {
                    return None;
                }
                self.flatten_part(node.child_by_field_name("left")?, parts)?;
                self.flatten_part(node.child_by_field_name("right")?, parts)
            }
            _ => None,
        }
    }

    /// Evaluate a string expression into a (ptr, len) local pair.
    /// Single-source values alias without copying; concatenations
    /// format numeric parts, sum lengths, allocate once, and copy
    /// left-to-right.
    fn materialize(&mut self, node: tree_sitter::Node) -> Option<(u32, u32)> {
        let mut parts = Vec::new();
        self.flatten_part(node, &mut parts)?;

        if parts.len() == 1 {
            match parts[0] {
                StrPart::Pair { ptr, len } => return Some((ptr, len)),
                StrPart::Lit { off, len } => {
                    let ptr_local = self.asm.local(ValType::I32);
                    let len_local = self.asm.local(ValType::I32);
                    self.asm.extend([
                        I::I32Const(off as i32),
                        I::LocalSet(ptr_local),
                        I::I32Const(len as i32),
                        I::LocalSet(len_local),
                    ]);
                    return Some((ptr_local, len_local));
                }
                StrPart::Num(_) => {}
            }
        }

        // Resolve numeric parts to formatted pairs, in order.
        let mut resolved: Vec<ResolvedPart> = Vec::new();
        for part in parts {
            match part {
                StrPart::Num(expr) => {
                    self.num_expr(expr)?;
                    let ptr = self.asm.local(ValType::I32);
                    let len = self.asm.local(ValType::I32);
                    self.asm.extend([
                        I::Call(STR_FN_FMT),
                        I::LocalSet(len),
                        I::LocalSet(ptr),
                    ]);
                    resolved.push(ResolvedPart::Pair { ptr, len });
                }
                StrPart::Pair { ptr, len } => resolved.push(ResolvedPart::Pair { ptr, len }),
                StrPart::Lit { off, len } => resolved.push(ResolvedPart::Lit { off, len }),
            }
        }

        let lit_total: u32 = resolved
            .iter()
            .map(|part| match part {
                ResolvedPart::Lit { len, .. } => *len,
                ResolvedPart::Pair { .. } => 0,
            })
            .sum();
        let total = self.asm.local(ValType::I32);
        self.asm.i(I::I32Const(lit_total as i32));
        for part in &resolved {
            if let ResolvedPart::Pair { len, .. } = part {
                self.asm.extend([I::LocalGet(*len), I::I32Add]);
            }
        }
        self.asm.i(I::LocalSet(total));

        let out = self.asm.local(ValType::I32);
        let write = self.asm.local(ValType::I32);
        self.asm.extend([
            I::LocalGet(total),
            I::Call(JSON_FN_ALLOC),
            I::LocalTee(out),
            I::LocalSet(write),
        ]);
        for part in &resolved {
            match part {
                ResolvedPart::Lit { off, len } => self.asm.extend([
                    I::LocalGet(write),
                    I::I32Const(*off as i32),
                    I::I32Const(*len as i32),
                    I::MemoryCopy {
                        src_mem: 0,
                        dst_mem: 0,
                    },
                    I::LocalGet(write),
                    I::I32Const(*len as i32),
                    I::I32Add,
                    I::LocalSet(write),
                ]),
                ResolvedPart::Pair { ptr, len } => self.asm.extend([
                    I::LocalGet(write),
                    I::LocalGet(*ptr),
                    I::LocalGet(*len),
                    I::MemoryCopy {
                        src_mem: 0,
                        dst_mem: 0,
                    },
                    I::LocalGet(write),
                    I::LocalGet(*len),
                    I::I32Add,
                    I::LocalSet(write),
                ]),
            }
        }
        Some((out, total))
    }

    /// Numeric expression → one f64 on the stack. The numeric-loop
    /// subset minus arrays, bitwise, and user helper calls.
    fn num_expr(&mut self, node: tree_sitter::Node) -> Option<()> {
        match node.kind() {
            "number" => {
                let value = parse_js_number(self.text(node))?;
                self.asm.i(I::F64Const(value.into()));
                Some(())
            }
            "identifier" => {
                let name = self.text(node);
                match name {
                    "Infinity" => {
                        self.asm.i(I::F64Const(f64::INFINITY.into()));
                        Some(())
                    }
                    "NaN" => {
                        self.asm.i(I::F64Const(f64::NAN.into()));
                        Some(())
                    }
                    _ => {
                        let ident = js_ident(name)?;
                        match self.slot(&ident) {
                            Some(StrSlot::Num(local)) => {
                                self.asm.i(I::LocalGet(local));
                                Some(())
                            }
                            _ => None,
                        }
                    }
                }
            }
            "member_expression" => {
                let field = field_of_member(node, self.source, self.param)?;
                let slots = *self.field_slots.get(&field)?;
                if slots.mode != FieldMode::Num {
                    return None;
                }
                self.asm.i(I::LocalGet(slots.num));
                Some(())
            }
            "true" => {
                self.asm.i(I::F64Const(1.0.into()));
                Some(())
            }
            "false" => {
                self.asm.i(I::F64Const(0.0.into()));
                Some(())
            }
            "parenthesized_expression" => self.num_expr(node.named_child(0)?),
            "unary_expression" => {
                let op = self.op_text(node)?;
                match op {
                    "-" => {
                        self.num_expr(node.child_by_field_name("argument")?)?;
                        self.asm.i(I::F64Neg);
                        Some(())
                    }
                    "+" => self.num_expr(node.child_by_field_name("argument")?),
                    "!" => {
                        self.num_expr(node.child_by_field_name("argument")?)?;
                        self.emit_truthy();
                        self.asm.extend([I::I32Eqz, I::F64ConvertI32U]);
                        Some(())
                    }
                    _ => None,
                }
            }
            "binary_expression" => {
                let left = node.child_by_field_name("left")?;
                let right = node.child_by_field_name("right")?;
                let op = self.op_text(node)?;
                match op {
                    "+" | "-" | "*" | "/" => {
                        self.num_expr(left)?;
                        self.num_expr(right)?;
                        self.asm.i(match op {
                            "+" => I::F64Add,
                            "-" => I::F64Sub,
                            "*" => I::F64Mul,
                            _ => I::F64Div,
                        });
                        Some(())
                    }
                    "%" => {
                        self.num_expr(left)?;
                        self.num_expr(right)?;
                        self.asm.i(I::Call(STR_FN_MOD));
                        Some(())
                    }
                    "<" | "<=" | ">" | ">=" => {
                        self.num_expr(left)?;
                        self.num_expr(right)?;
                        self.asm.i(match op {
                            "<" => I::F64Lt,
                            "<=" => I::F64Le,
                            ">" => I::F64Gt,
                            _ => I::F64Ge,
                        });
                        self.asm.i(I::F64ConvertI32U);
                        Some(())
                    }
                    "==" | "===" | "!=" | "!==" => {
                        let (tl, tr) = (self.sty(left)?, self.sty(right)?);
                        if tl == STy::Str || tr == STy::Str {
                            self.emit_str_eq(left, right, tl, tr)?;
                            if op.starts_with('!') {
                                self.asm.i(I::I32Eqz);
                            }
                            self.asm.i(I::F64ConvertI32U);
                            return Some(());
                        }
                        if tl != STy::Num || tr != STy::Num {
                            return None;
                        }
                        self.num_expr(left)?;
                        self.num_expr(right)?;
                        self.asm.i(if op.starts_with('!') {
                            I::F64Ne
                        } else {
                            I::F64Eq
                        });
                        self.asm.i(I::F64ConvertI32U);
                        Some(())
                    }
                    "&&" | "||" => {
                        let tmp = self.asm.local(ValType::F64);
                        self.num_expr(left)?;
                        self.asm.i(I::LocalSet(tmp));
                        self.asm.i(I::LocalGet(tmp));
                        self.emit_truthy();
                        self.asm.i(I::If(BlockType::Result(ValType::F64)));
                        if op == "&&" {
                            self.num_expr(right)?;
                            self.asm.i(I::Else);
                            self.asm.i(I::LocalGet(tmp));
                        } else {
                            self.asm.i(I::LocalGet(tmp));
                            self.asm.i(I::Else);
                            self.num_expr(right)?;
                        }
                        self.asm.i(I::End);
                        Some(())
                    }
                    _ => None,
                }
            }
            "call_expression" => {
                let callee = node.child_by_field_name("function")?;
                if callee.kind() != "member_expression" {
                    return None;
                }
                let object = callee.child_by_field_name("object")?;
                let property = callee.child_by_field_name("property")?;
                if object.kind() != "identifier" || self.text(object) != "Math" {
                    return None;
                }
                let args_node = node.child_by_field_name("arguments")?;
                let mut args: Vec<tree_sitter::Node> = Vec::new();
                let mut walker = args_node.walk();
                for arg in args_node.named_children(&mut walker) {
                    if arg.kind() == "comment" {
                        continue;
                    }
                    args.push(arg);
                }
                self.math_intrinsic(self.text(property), &args)
            }
            _ => None,
        }
    }

    fn math_intrinsic(&mut self, name: &str, args: &[tree_sitter::Node]) -> Option<()> {
        match (name, args.len()) {
            ("floor", 1) | ("ceil", 1) | ("trunc", 1) | ("abs", 1) | ("sqrt", 1) => {
                self.num_expr(args[0])?;
                self.asm.i(match name {
                    "floor" => I::F64Floor,
                    "ceil" => I::F64Ceil,
                    "trunc" => I::F64Trunc,
                    "abs" => I::F64Abs,
                    _ => I::F64Sqrt,
                });
                Some(())
            }
            ("round", 1) => {
                self.num_expr(args[0])?;
                self.asm.i(I::Call(STR_FN_ROUND));
                Some(())
            }
            ("min", 0) => {
                self.asm.i(I::F64Const(f64::INFINITY.into()));
                Some(())
            }
            ("max", 0) => {
                self.asm.i(I::F64Const(f64::NEG_INFINITY.into()));
                Some(())
            }
            ("min", _) | ("max", _) => {
                let helper = if name == "min" { STR_FN_MIN } else { STR_FN_MAX };
                self.num_expr(args[0])?;
                for arg in &args[1..] {
                    self.num_expr(*arg)?;
                    self.asm.i(I::Call(helper));
                }
                Some(())
            }
            _ => None,
        }
    }
}

/// (v: f64) -> (ptr: i32, len: i32): format an integral f64 as decimal
/// digits with an optional '-' sign into a fresh allocation. The
/// fibonacci digit-formatting convention (integral, |v| ≤ 2^53)
/// extended with the sign; non-integral values (incl. NaN) and
/// out-of-range magnitudes TRAP — walker jurisdiction.
fn helper_fmt_int() -> FuncSpec {
    let mut a = Asm::new(1); // v: f64
    let neg = a.local(ValType::I32);
    let v = a.local(ValType::I64);
    let digits = a.local(ValType::I32);
    let out = a.local(ValType::I32);
    let t = a.local(ValType::I32);

    a.extend([
        // non-integral (incl. NaN) → decline
        I::LocalGet(0),
        I::LocalGet(0),
        I::F64Trunc,
        I::F64Ne,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        // |v| > 2^53 → decline
        I::LocalGet(0),
        I::F64Abs,
        I::F64Const(9007199254740992.0.into()),
        I::F64Gt,
        I::If(BlockType::Empty),
        I::Unreachable,
        I::End,
        // neg = v < 0 (note: -0 formats as "0", like JS String(-0))
        I::LocalGet(0),
        I::F64Const(0.0.into()),
        I::F64Lt,
        I::LocalSet(neg),
        // v = |value| as i64; digits reversed into SCRATCH
        I::LocalGet(0),
        I::F64Abs,
        I::I64TruncSatF64S,
        I::LocalSet(v),
        I::I32Const(0),
        I::LocalSet(digits),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::I32Const(SCRATCH_BASE as i32),
        I::LocalGet(digits),
        I::I32Add,
        I::LocalGet(v),
        I::I64Const(10),
        I::I64RemU,
        I::I32WrapI64,
        I::I32Const(b'0' as i32),
        I::I32Add,
        I::I32Store8(memarg8(0)),
        I::LocalGet(digits),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(digits),
        I::LocalGet(v),
        I::I64Const(10),
        I::I64DivU,
        I::LocalTee(v),
        I::I64Eqz,
        I::BrIf(1),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    // out = alloc(digits + neg); optional sign; copy reversed
    a.extend([
        I::LocalGet(digits),
        I::LocalGet(neg),
        I::I32Add,
        I::Call(JSON_FN_ALLOC),
        I::LocalSet(out),
        I::LocalGet(neg),
        I::If(BlockType::Empty),
        I::LocalGet(out),
        I::I32Const(b'-' as i32),
        I::I32Store8(memarg8(0)),
        I::End,
        I::I32Const(0),
        I::LocalSet(t),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::LocalGet(t),
        I::LocalGet(digits),
        I::I32GeS,
        I::BrIf(1),
        // out[neg + t] = scratch[digits - 1 - t]
        I::LocalGet(out),
        I::LocalGet(neg),
        I::I32Add,
        I::LocalGet(t),
        I::I32Add,
        I::I32Const(SCRATCH_BASE as i32),
        I::LocalGet(digits),
        I::I32Add,
        I::I32Const(1),
        I::I32Sub,
        I::LocalGet(t),
        I::I32Sub,
        I::I32Load8U(memarg8(0)),
        I::I32Store8(memarg8(0)),
        I::LocalGet(t),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(t),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.extend([
        I::LocalGet(out),
        I::LocalGet(digits),
        I::LocalGet(neg),
        I::I32Add,
    ]);

    FuncSpec {
        params: vec![ValType::F64],
        results: vec![ValType::I32, ValType::I32],
        locals: a.locals,
        ins: a.ins,
    }
}

/// (pa, la, pb, lb) -> i32: byte equality of two memory runs. Bounded
/// by the operand lengths (no fuel needed).
fn helper_str_eq() -> FuncSpec {
    let mut a = Asm::new(4);
    let i = a.local(ValType::I32);
    a.extend([
        I::LocalGet(1),
        I::LocalGet(3),
        I::I32Ne,
        I::If(BlockType::Empty),
        I::I32Const(0),
        I::Return,
        I::End,
        I::I32Const(0),
        I::LocalSet(i),
    ]);
    a.i(I::Block(BlockType::Empty));
    a.i(I::Loop(BlockType::Empty));
    a.extend([
        I::LocalGet(i),
        I::LocalGet(1),
        I::I32GeS,
        I::BrIf(1),
        I::LocalGet(0),
        I::LocalGet(i),
        I::I32Add,
        I::I32Load8U(memarg8(0)),
        I::LocalGet(2),
        I::LocalGet(i),
        I::I32Add,
        I::I32Load8U(memarg8(0)),
        I::I32Ne,
        I::If(BlockType::Empty),
        I::I32Const(0),
        I::Return,
        I::End,
        I::LocalGet(i),
        I::I32Const(1),
        I::I32Add,
        I::LocalSet(i),
        I::Br(0),
    ]);
    a.i(I::End);
    a.i(I::End);
    a.i(I::I32Const(1));

    FuncSpec {
        params: vec![ValType::I32; 4],
        results: vec![ValType::I32],
        locals: a.locals,
        ins: a.ins,
    }
}

// Keep the CustomSection import honest even though the manifest section
// is hand-appended (concatenation) rather than re-encoded.
#[allow(dead_code)]
fn manifest_custom_section(json: &[u8]) -> CustomSection<'_> {
    CustomSection {
        name: Cow::Borrowed(BETTI_WASM_MANIFEST_SECTION),
        data: Cow::Borrowed(json),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn sha256_matches_nist_abc_vector() {
        assert_eq!(
            sha256_hex(b"abc"),
            "ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad"
        );
        assert_eq!(
            sha256_hex(b""),
            "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"
        );
    }

    #[test]
    fn json_fixture_modules_validate() {
        for bytes in [
            emit_echo_module(),
            emit_fanout_module(),
            emit_fibonacci_module(),
        ] {
            wasmparser::validate(&bytes).expect("fixture module should validate");
        }
    }

    #[test]
    fn numeric_loop_module_validates_and_declines_outside_class() {
        let src = "export function main(n) {\n  let s = 0;\n  for (let i = 0; i < n; i++) { s = s + i; }\n  return s;\n}\n";
        let module = numeric_loop_wasm(src, "main").expect("sum loop is in the class");
        wasmparser::validate(&module.bytes).expect("numeric module should validate");

        let recursive =
            "export function main(n) { if (n < 2) return n; return main(n - 1) + main(n - 2); }\n";
        assert!(
            numeric_loop_wasm(recursive, "main").is_none(),
            "recursion is outside the certified class"
        );
        assert!(
            numeric_loop_wasm("export function main(a, b) { return a + b; }", "main").is_none(),
            "multi-param protocol unsupported"
        );
        assert!(
            numeric_loop_wasm("export function main() { return foo; }", "main").is_none(),
            "unknown identifiers refuse"
        );
        assert!(
            numeric_loop_wasm("export function main(n) { return Math.pow(n, 2); }", "main")
                .is_none(),
            "Math.pow is excluded"
        );
    }

    #[test]
    fn string_class_modules_validate_and_are_deterministic() {
        let programs = [
            "export function main(input) { return `hello:${input.name}!`; }\n",
            "export function main(input) { return input.first + \":\" + input.last; }\n",
            "export function main(input) { return `n is ${input.n}`; }\n",
            "export function main(input) { return input.n * 2 + 1; }\n",
            "export function main(input) { if (input.role === \"admin\") { return \"yes\"; } return \"no\"; }\n",
            "export function main(input) { let x = input.name; return `hi ${x}`; }\n",
        ];
        for src in programs {
            let module = string_class_wasm(src, "main")
                .unwrap_or_else(|| panic!("program should be in the scalar-string class:\n{src}"));
            wasmparser::validate(&module.bytes).expect("string module should validate");
            let again = string_class_wasm(src, "main").expect("re-emits");
            assert_eq!(module.bytes, again.bytes, "emission must be deterministic");
            // Zero imports (certified-direct contract).
            for payload in wasmparser::Parser::new(0).parse_all(&module.bytes) {
                if let wasmparser::Payload::ImportSection(reader) = payload.expect("parse") {
                    assert_eq!(reader.count(), 0, "no imports allowed");
                }
            }
        }
    }

    #[test]
    fn string_class_fails_closed_outside_the_class() {
        let refusals = [
            // string methods / length are v1-excluded
            "export function main(input) { return input.name.length; }\n",
            "export function main(input) { return input.name.slice(1); }\n",
            "export function main(input) { return input.name.toUpperCase(); }\n",
            // loops over anything are outside the string class
            "export function main(input) { let s = \"\"; for (let i = 0; i < 3; i++) { s = s + \"x\"; } return s; }\n",
            "export function main(input) { while (input.n > 0) { return \"x\"; } return \"y\"; }\n",
            // bare parameter use
            "export function main(input) { return input; }\n",
            "export function main(input) { return `v:${input}`; }\n",
            // nested member reads
            "export function main(input) { return `v:${input.a.b}`; }\n",
            // computed member reads
            "export function main(input) { return `v:${input[\"a\"]}`; }\n",
            // optional chaining
            "export function main(input) { return `v:${input?.a}`; }\n",
            // a field cannot be both a strict string and a number
            "export function main(input) { if (input.x === \"a\") { return input.x * 2; } return 0; }\n",
            // ambiguous + (JS could add or concatenate)
            "export function main(input) { return input.a + input.b; }\n",
            "export function main(input) { return input.a + 1; }\n",
            // user helper calls are outside the class
            "function up(s) { return s; }\nexport function main(input) { return up(input.name); }\n",
            // escape sequences in literals are walker jurisdiction
            "export function main(input) { return \"a\\nb\"; }\n",
            "export function main(input) { return `a\\tb${input.x}`; }\n",
            // literals that would need JSON output escaping
            "export function main(input) { return 'he said \"hi\"'; }\n",
            // string augmented assignment is v1-excluded
            "export function main(input) { let s = \"a\"; s += input.name; return s; }\n",
            // multi-parameter entries are outside the class
            "export function main(a, b) { return `v:${a.x}`; }\n",
            // update on a string local
            "export function main(input) { let s = \"a\"; s++; return s; }\n",
        ];
        for src in refusals {
            assert!(
                string_class_wasm(src, "main").is_none(),
                "program must refuse the scalar-string compile:\n{src}"
            );
        }
        // ...and the multi-param numeric class must not claim them either.
        assert!(numeric_loop_wasm("export function main(input) { return `hello:${input.name}!`; }\n", "main").is_none());
    }

    #[test]
    fn manifest_custom_section_appends_and_reparses() {
        let src = "export function main() { return 41 + 1; }\n";
        let module = numeric_loop_wasm(src, "main").expect("constant fold is in the class");
        let manifest = br#"{"artifact_version":"betti-wasm/1"}"#;
        let with_section = append_manifest_section(module.bytes.clone(), manifest);
        wasmparser::validate(&with_section).expect("module with custom section validates");

        // The custom section must be discoverable by name.
        let mut found = false;
        for payload in wasmparser::Parser::new(0).parse_all(&with_section) {
            if let wasmparser::Payload::CustomSection(reader) = payload.expect("parse") {
                if reader.name() == BETTI_WASM_MANIFEST_SECTION {
                    assert_eq!(reader.data(), manifest);
                    found = true;
                }
            }
        }
        assert!(found, "gnosis-betti-manifest custom section present");
    }
}
